INSERT INTO `university` (`id`, `name`, `country`, `banner_image`, `logo_image`, `city`, `description`, `link`, `ranking`, `established_year`, `enroll_students`) VALUES
(1, 'Acadia University', 'Canada', '/catalog/University_Banner/Acadia university banner image.png', '/catalog/University_Favicon/canada/Acadia University Favicon.png', 'Wolfville, Nova Scotia, Canada', 'Acadia University is a public undergraduate-focused university known for liberal arts, science, and small class sizes.', 'https://www.acadiau.ca', 'Not ranked globally', '1838', '4000'),
(2, 'Adelphi University', 'United States', '0', '/catalog/University_Favicon/usa/Adelphi University_Favicon.png', 'Garden City, New York, USA', 'Adelphi University is a private university offering strong programs in nursing, psychology, and business.', 'https://www.adelphi.edu', 'Not ranked globally', '1896', '7500'),
(3, 'Adler University', 'Canada', '/catalog/University_Banner/Adler University  banner.png', '/catalog/University_Favicon/canada/Adler University favicon.png', 'Vancouver, British Columbia, Canada', 'Adler University is a private university specializing in psychology, counseling, and social justice education.', 'https://www.adler.edu', 'Not ranked globally', '1952', '1600'),
(4, 'Albertus Magnus College', 'USA', '0', '0', 'New Haven, Connecticut, USA', 'Albertus Magnus College is a private liberal arts college focused on adult and professional education.', 'https://www.albertus.edu', 'Not ranked globally', '1925', '1200'),
(5, 'Alexander College', 'Canada', '0', '/catalog/University_Favicon/canada/Alexander College_Favicon.png', 'Burnaby, British Columbia', 'Alexander College is a private post-secondary institution offering university-transfer programs, Associate of Arts and Associate of Science degrees, and English for Academic Purposes, with pathways to public universities in British Columbia.', 'https://alexandercollege.ca', '#11505 in the world by Webometrics', '2006', '3,500'),
(6, 'Algonquin College', 'Canada', '/catalog/University_Banner/canada-banner/Algonquin College  banner.png', '/catalog/University_Favicon/canada/Algoquinn collegeFavicon.png', 'Ottawa, Ontario', 'Algonquin College of Applied Arts and Technology is a publicly funded college located in Ottawa, Ontario, Canada, with additional campuses in Perth and Pembroke. It offers more than 200 applied programs including bachelor?s degrees, diplomas, and certificates, emphasizing hands-on, career-oriented learning and strong industry connections. The college is one of the largest polytechnic institutions in Eastern Ontario and is recognized for its practical education and research partnerships.', 'https://www.algonquincollege.com', 'Global (QS World University Rankings 2022): Ranked #1531 globally', '1967', '25191'),
(7, 'Alliant International University', 'United States', '0', '/catalog/University_logo//1723019683-Alliant%20International%20University_Favicon.png', 'San Diego, California, USA', 'Alliant International University is a private university specializing in psychology, education, and health sciences.', 'https://www.alliant.edu', 'Not ranked globally', '1952', '3500'),
(8, 'American Collegiate Live', 'United States', '0', '0', 'New York, USA', 'American Collegiate Live is an online pathway program designed to help international students transition into U.S. universities. It offers first-year academic coursework combined with academic advising and English language support. The program focuses on flexibility, credit transfer, and preparation for on-campus degree study in the United States.', 'https://americancollegiate.com', 'Not ranked (pathway program)', '2020', '1000'),
(9, 'American Collegiate, Washington, DC', 'United States', '0', '/catalog/University_logo//1723120602-American%20Collegiate-%20Washington-%20DC_Favicon.png', 'Washington, D.C., USA', 'American Collegiate, Washington DC provides pathway programs in partnership with US universities.', 'https://americancollegiate.com', 'Not ranked globally', '2020', '1000'),
(10, 'American University', 'United States', '0', '/catalog/University_logo//1723120632-American%20University_Favicon.png', 'Washington, D.C., USA', 'American University is a private research university known for international relations, law, and public affairs.', 'https://www.american.edu', 'Top 400 (QS)', '1893', '14000'),
(11, 'Anglia Ruskin University', 'united kingdom', '/catalog/University_Banner/Anglia Ruskin University Banner.jpg', '/catalog/University_Favicon/Anglia Ruskin University_Favicon.png', 'Cambridge & Chelmsford, England, UK', 'Anglia Ruskin University is a large public university offering a wide range of undergraduate and postgraduate programs. It is known for applied research, business, health, engineering, and creative arts. The university emphasizes employability, innovation, and community impact. It operates campuses across East England and London.', 'https://www.aru.ac.uk', '501?600 (THE)', '1858', '35000'),
(12, 'Anglia Ruskin University - London Campus', 'united kingdom', '/catalog/University_Banner/Anglia Ruskin University Banner.jpg', '/catalog/University_Favicon/Anglia Ruskin University_Favicon.png', 'London, England, UK', 'Anglia Ruskin University ? London Campus delivers business, finance, and management programs in the UK capital.', 'https://www.aru.ac.uk', 'Top 350 (QS)', '1858', '1200'),
(13, 'Arkansas State University', 'United States', '0', '/catalog/University_Favicon/usa/Arkansas State University_Favicon.png', 'Jonesboro, Arkansas, USA', 'Arkansas State University is a public research university offering a wide range of academic programs. It is known for business, engineering, education, agriculture, and health sciences. The university emphasizes research growth, community engagement, and student success initiatives.', 'https://www.astate.edu', 'Not ranked in major global rankings', '1909', '13000'),
(14, 'Aston University', 'united kingdom', '/catalog/University_Banner/Aston University Banner.jpg', '/catalog/University_Favicon/Aston University_Favicon.png', 'Birmingham, England, UK', 'Aston University is a public research university known for business, engineering, technology, and health sciences. It has a strong focus on employability, placements, and industry collaboration. The university emphasizes practical learning and research impact. Its business school is highly regarded internationally.', 'https://www.aston.ac.uk', 'Top 500 (QS)', '1895', '15500'),
(15, 'Aston University - London Campus', '', '/catalog/University_Banner//1736400076-Aston-University-Banner.jpg', '/catalog/University_logo//1736400076-Aston-University_Favicon.png', 'London, England, UK', 'Aston University ? London Campus delivers postgraduate business and leadership programs from Aston University.', 'https://www.aston.ac.uk', 'Top 450 (QS)', '1895', '1000'),
(16, 'Atlantic Technological University (GMIT)', 'Ireland', '/catalog/University_Banner/Ireland/GalwayMayoInstituteofTechnologybanner.png', '/catalog/University_Favicon/ireland/Atlantic Technological University_Favicon.png', 'Galway, Ireland', 'Atlantic Technological University, formed from institutes including GMIT, is a public multi-campus technological university. It offers programs in engineering, science, business, computing, health, and creative arts. The university focuses on applied research, innovation, and industry collaboration. It supports regional growth and career-focused education.', 'https://www.atu.ie', 'Not ranked globally', '2022', '23000'),
(17, 'Atlantic Technological University (IT Sligo)', 'Ireland', '/catalog/University_Banner/Ireland/InstituteofTechnologySligobanner.png', '/catalog/University_Favicon/ireland/Atlantic Technological University_Favicon.png', 'Sligo, Sligo', 'Atlantic Technological University (ATU) is a public technological university in Ireland, established on 1 April 2022 through the merger of Galway-Mayo Institute of Technology, Institute of Technology Sligo (IT Sligo), and Letterkenny IT. It offers a wide range of undergraduate, postgraduate, and doctoral programs focused on practical, industry-linked education, research excellence, and strong graduate outcomes across multiple campuses in the west and north-west of Ireland.', 'https://www.atu.ie/', '#1849 in the world by UniRank', '2022', '10000'),
(18, 'Atlantic Technological University (LYIT)', 'Ireland', '/catalog/University_Banner/Ireland/LetterkennyInstituteofTechnologybanner.png', '/catalog/University_Favicon/ireland/Atlantic Technological University_Favicon.png', 'Letterkenny, Ireland', 'Atlantic Technological University ? Donegal (LYIT) is a public technological university offering applied and professional programs.', 'https://www.atu.ie', 'Not ranked globally', '1971', '4500'),
(19, 'Auburn University at Alabama', 'United States', '0', '/catalog/University_Favicon/usa/Auburn University at Alabama_Favicon.png', 'Auburn, Alabama, USA', 'Auburn University is a major public research university and flagship institution of Alabama. It is known for strong programs in engineering, business, agriculture, and sciences. The university emphasizes research excellence, innovation, and a vibrant campus life with strong alumni networks.', 'https://www.auburn.edu', '#285 in the world by QS World University Rankings', '1856', '30000'),
(20, 'Auburn University at Montgomery', 'United States', '0', '/catalog/University_Favicon/usa/Auburn University at Montgomery_Favicon.png', 'Montgomery, Alabama, USA', 'Auburn University at Montgomery is a public university offering undergraduate and graduate programs.', 'https://www.aum.edu', 'Not ranked globally', '1967', '6000'),
(21, 'Austin College', 'United States', '0', '0', 'Sherman, Texas', 'Austin College is a private liberal arts college located in Sherman, Texas, USA. Founded in 1849, it offers a broad range of undergraduate programs in arts, sciences, business, and pre-professional fields with a focus on personalized education, small class sizes, and experiential learning. The college emphasizes student-faculty engagement and a residential community that supports academic growth and leadership development.', 'https://www.austincollege.edu', '#3223 in the world by EduRank', '1849', '1286'),
(22, 'Avila University', 'United States', '0', '0', 'Kansas City, Missouri, USA', 'Avila University is a private Catholic university focused on liberal arts and professional education. It emphasizes small class sizes, personalized learning, and values-based education. The university offers programs in business, education, health sciences, psychology, and arts with strong community involvement.', 'https://www.avila.edu', 'Not ranked in major global rankings', '1916', '1700'),
(23, 'Bangor University', 'united kingdom', '/catalog/University_Banner/Bangor University  Banner.png', '/catalog/University_Favicon/Bangor UniversityFavicon.png', 'Bangor, Wales, UK', 'Bangor University is a public research university known for strong teaching and research excellence. It offers a wide range of undergraduate and postgraduate programs with strengths in environmental sciences, oceanography, psychology, and business. The university emphasizes sustainability, research impact, and student support.', 'https://www.bangor.ac.uk', '#474 in the world by QS World University Rankings', '1884', '10000'),
(24, 'Barton College', 'United States', '0', '0', 'Wilson, North Carolina, USA', 'Barton College is a private liberal arts college offering undergraduate and graduate programs. It emphasizes small class sizes, personalized education, and leadership development. The college is known for programs in education, nursing, business, and the arts with a strong community focus.', 'https://www.barton.edu', 'Not ranked in major global rankings', '1902', '1200'),
(25, 'Bellarmine University', 'United States', '0', '0', 'Louisville, Kentucky', 'Bellarmine University is a private, independent Catholic university located in Louisville, Kentucky, USA. It offers more than 50 undergraduate majors and a wide range of graduate and doctoral programs with a strong emphasis on career outcomes, hands-on learning, and personalized education. The university blends a liberal arts foundation with professional preparation and global experiences in a close-knit campus community.', 'https://www.bellarmine.edu', '#2961 in the world (EduRank 2025)', '1950', '3759'),
(26, 'Belmont University', 'United States', '0', '0', 'Nashville, Tennessee, USA', 'Belmont University is a private Christian university known for music, business, and healthcare programs.', 'https://www.belmont.edu', 'Not ranked globally', '1890', '8800'),
(27, 'Berkeley College', 'United States', '0', '/catalog/University_logo//1723019793-Berkeley%20College_Favicon_Favicon.png', 'New York City', 'Berkeley College is a private, for-profit college in the United States, offering career-focused associate?s, bachelor?s and master?s degree programs in areas such as business, health services, criminal justice, fashion, and technology. Founded in 1931, it operates campuses in New York City and New Jersey, and also serves students through Berkeley College Online?. The college emphasizes practical skills and workforce readiness with a focus on student support and professional success.', 'https://www.berkeleycollege.edu', '#8495 globally (Webometrics World University Ranking)', '1931', '4,128'),
(28, 'Bethel College', 'United States', '0', '0', 'North Newton, Kansas, USA', 'Bethel College is a private liberal arts college focused on undergraduate education and personal academic development. It emphasizes small class sizes, close faculty interaction, and a strong community environment. The college offers programs in arts, sciences, business, and education with a values-based learning approach.', 'https://www.bethelks.edu', 'Not ranked in major global rankings', '1887', '500'),
(29, 'Birmingham City University', 'united kingdom', '/catalog/University_Banner/Birmingham City University banner.png', '/catalog/University_Favicon/Birmingham City University_Favicon.png', 'Birmingham, England, UK', 'Birmingham City University is a public university known for its strong focus on practical education and creative industries. It offers programs in arts, design, media, business, engineering, and health. The university emphasizes employability, industry collaboration, and modern campus facilities.', 'https://www.bcu.ac.uk', '#1001?1200 in the world by THE World University Rankings', '1843', '24000'),
(30, 'Birmingham City University - Dubai', 'united arab emirates', '0', '/catalog/University_Favicon/Birmingham City University_Favicon.png', 'Dubai, United Arab Emirates', 'Birmingham City University ? Dubai Campus offers UK-accredited degrees in business, media, and computing.', 'https://www.bcu.ac.uk/dubai', 'Top 1000 (QS ? parent university)', '2017', '1,500'),
(31, 'Blackburn College', 'United States', '0', '0', 'Carlinville, Illinois', 'Blackburn College is a private liberal arts college affiliated with the Presbyterian Church (USA). Founded in 1837, it is one of the oldest private colleges in Illinois and known for its distinctive student-managed Work Program ? part of the federally recognized Work Colleges consortium ? where students work on campus to earn tuition discounts and gain real-world experience. The college emphasizes personalized attention, hands-on learning, service, and leadership development across a range of undergraduate majors.', 'https://www.blackburn.edu', '#5119 in the world by EduRank', '1837', '513'),
(32, 'Brandeis International Business School', 'United States', '0', '/catalog/University_Favicon/usa/Brandeis International Business School_Favicon.png', 'Waltham, Massachusetts, USA', 'Brandeis International Business School is the graduate business school of Brandeis University focusing on global business and finance.', 'https://www.brandeis.edu', 'Top 500 (QS ? parent university)', '1948', '900'),
(33, 'Bridgewater College', 'United States', '0', '0', 'Bridgewater, Virginia, USA', 'Bridgewater College is a private liberal arts college emphasizing personalized education and community values. It offers undergraduate programs across arts, sciences, business, and education. The college focuses on experiential learning, leadership development, and preparing students for meaningful careers and service.', 'https://www.bridgewater.edu', 'Not ranked in major global rankings', '1880', '1600'),
(34, 'Brunel University London', 'united kingdom', '/catalog/University_Banner/Brunel University London Banner.png', '/catalog/University_Favicon/Brunel University London_Favicon.png', 'Uxbridge, London', 'Brunel University London is a public research university named after the Victorian engineer Isambard Kingdom Brunel. It became a university in 1966 and offers a wide range of undergraduate, postgraduate, and research programmes across engineering, business, arts, health, and sciences. Brunel emphasises industry-focused education, strong international community, and practical research opportunities.', 'https://www.brunel.ac.uk', '#385 (QS World University Rankings 2026)', '1966', '13125'),
(35, 'Buckinghamshire New University', 'united kingdom', '0', '/catalog/University_Favicon/Buckinghamshire New University_Favicon.png', 'High Wycombe, England', 'Buckinghamshire New University (BNU) is a public university located in High Wycombe, Buckinghamshire, England, UK. It offers a wide range of undergraduate and postgraduate programs in areas such as business, creative arts, health, computing, and social sciences with an emphasis on practical, career-focused education and student satisfaction. Originally founded as a School of Science and Art in 1891, it gained full university status in 2007.', 'https://www.bucks.ac.uk', '#2862 globally (EduRank 2025)', '1891', '9966'),
(36, 'California Lutheran University', 'United States', '0', '/catalog/University_Favicon/usa/California Lutheran University_Favicon.png', 'Thousand Oaks, California', 'California Lutheran University is a private university offering undergraduate and graduate programs rooted in liberal arts education. It emphasizes small class sizes, personalized learning, and strong faculty-student interaction. The university is known for programs in business, psychology, education, and sciences, with a focus on ethical leadership and community engagement.', 'https://www.callutheran.edu', '#3200+ in the world by EduRank', '1959', '3200'),
(37, 'California State University East Bay', 'United States', '0', '/catalog/University_Favicon/usa/California State University East Bay_Favicon.png', 'Hayward, California, USA', 'California State University East Bay is a public university within the CSU system focused on teaching and applied learning. It offers undergraduate and graduate programs in business, education, sciences, and arts. The university emphasizes student success, community engagement, and regional workforce development.', 'https://www.csueastbay.edu', 'Not ranked in major global rankings', '1957', '14000'),
(38, 'California State University Sacramento', 'United States', '0', '/catalog/University_Favicon/usa/California State University Sacramento_Favicon.png', 'Sacramento, California, United States', 'California State University, Sacramento is a public university located in Sacramento, California, USA. Part of the California State University (CSU) system, it offers a wide range of undergraduate, graduate, and doctoral programs with a focus on research, community engagement, and real-world learning. Known for its diverse student body and strong regional impact, the campus sits along the American River and serves as the capital city?s primary public university.', 'https://www.csus.edu', '#1064 globally (EduRank World University Rankings 2025)', '1947', '30,883'),
(39, 'California State University San Bernardino', 'United States', '0', '/catalog/University_logo//1723019947-California%20State%20University%20San%20Bernardino_Favicon.png', 'San Bernardino, California', 'California State University, San Bernardino (often abbreviated CSUSB) is a public research university and part of the California State University system, the largest four-year public university system in the United States. Established as a state college in 1965 and later gaining university status, CSUSB serves a diverse student body with more than 70 undergraduate and graduate degree programs spanning business, education, engineering, arts, health sciences, social sciences and more. It is known for strong community engagement, high social mobility outcomes, and a commitment to access, student success, and service.', 'https://www.csusb.edu', '#1410 in the world by EduRank', '1965', '17,900'),
(40, 'California State University San Marcos', 'United States', '0', '/catalog/University_logo//1723021414-California%20State%20University%20San%20Marcos_Favicon.png', 'San Marcos, California, USA', 'California State University San Marcos is a public university within the CSU system focused on teaching and applied learning. It offers undergraduate and graduate programs in business, education, sciences, and arts. The university emphasizes student success, community engagement, and regional impact.', 'https://www.csusm.edu', 'Not ranked in major global rankings', '1989', '16000'),
(41, 'California State University Sonoma State', 'United States', '0', '/catalog/University_logo//1723120745-California%20State%20University%20Sonoma%20State_Favicon.png', 'Rohnert Park, California, USA', 'Sonoma State University is a public liberal arts?focused university in the California State University system. It offers undergraduate and graduate programs with strengths in business, education, liberal arts, and sciences. The university emphasizes sustainability, experiential learning, and close faculty-student interaction.', 'https://www.sonoma.edu', 'Not ranked in major global rankings', '1961', '9000'),
(42, 'Cambrian College of Applied Arts And Technology', 'Canada', '/catalog/University_Banner/canada-banner/Cambrian College banner.png', '/catalog/University_Favicon/canada/Cambrian College Favicon.png', 'Sudbury, Ontario, Canada', 'Cambrian College of Applied Arts and Technology is a public college offering career-focused diploma and applied degree programs.', 'https://cambriancollege.ca', 'Not ranked globally', '1967', '7000'),
(43, 'Canada Enquiry', 'Canada', '0', '/catalog/University_Favicon/ireland/Enquiry_Favicon.png', 'Canada', 'Canada Enquiry is an education consultancy supporting applications to Canadian colleges and universities.', 'Not applicable', 'Not applicable', 'Not applicable', ''),
(44, 'Canadore College', 'Canada', '/catalog/University_Banner/canada-banner/Canadore College  banner.png', '/catalog/University_Favicon/canada/Canadore College Favicon.png', 'North Bay, Ontario, Canada', 'Canadore College is a public college offering career-focused diplomas, certificates, and applied degrees. It is known for aviation, health, business, engineering technology, and environmental programs. The college emphasizes experiential learning, industry partnerships, and regional workforce development.', 'https://www.canadorecollege.ca', 'Not ranked (college, not university)', '1967', '6500'),
(45, 'Canterbury Christ Church University', 'united kingdom', '0', '/catalog/University_Favicon/Canterbury Christ Church University_Favicon.png', 'Canterbury, England, UK', 'Canterbury Christ Church University is a public university offering a wide range of academic and professional programs. It is known for education, health, social sciences, business, and humanities. The university emphasizes employability, community engagement, and student support. It plays a key role in regional development and public service education.', 'https://www.canterbury.ac.uk', '1201?1500 (THE)', '1962', '17000'),
(46, 'Cape Breton University', 'Canada', '/catalog/University_Banner/canada-banner/Cape Breton University   banner.png', '/catalog/University_Favicon/canada/Cape Breton University Favicon.png', 'Cape Breton University', 'Cape Breton University (CBU) is a public university located in Sydney, Nova Scotia, Canada, known for its experiential learning, strong community engagement, and supportive academic environment. It offers a range of undergraduate and graduate programs across arts, sciences, business, health, and professional fields, with a focus on hands-on experience, research opportunities, and Indigenous learning leadership.', 'https://www.cbu.ca', '#2760 globally (EduRank 2025)', '1974', '3500'),
(47, 'Capilano University', 'Canada', '/catalog/University_Banner/canada-banner/Capilano University   banner.png', '/catalog/University_Favicon/canada/Capilano University Favicon.png', 'North Vancouver, British Columbia, Canada', 'Capilano University is a public university offering undergraduate and applied degree programs. It is known for arts, business, education, film, and environmental studies. The university emphasizes experiential learning, creativity, and close connections with local industries and communities.', 'https://www.capilanou.ca', 'Not ranked in major global rankings', '1968', '12000'),
(48, 'Cardiff Metropolitan University', 'united kingdom', '/catalog/University_Banner/Cardiff Metropolitan University-banner.png', '/catalog/University_Favicon/Cardiff Metropolitan University_Favicon.png', 'Cardiff, Wales', 'Cardiff Metropolitan University (often called Cardiff Met) is a public university in Cardiff, Wales, UK, known for career-focused and professionally oriented programmes in areas such as sport and health sciences, business and management, art and design, education, and technology. The institution emphasizes employability, practical learning, and strong industry links, with students from many countries and a vibrant campus culture.', 'https://cardiffmet.ac.uk', '1001 :(THE World University Rankings 2026)', '1996', '12000'),
(49, 'Cardiff University', 'united kingdom', '0', '/catalog/University_logo/Cardiff University.jpg', 'Cardiff, Wales', 'Cardiff University is a public research university and a member of the prestigious Russell Group of leading UK research-intensive institutions, known for strong programs across sciences, humanities, engineering, medicine, and social sciences.', 'https://www.cardiff.ac.uk', '#181 in the QS World University Rankings', '1883', '27,327'),
(50, 'Care Hope College', 'United States', '0', '0', 'California, USA', 'Care Hope College is a private institution focused on healthcare and allied health education.', 'https://www.carehope.edu/', 'Not ranked globally', '2010', '1000'),
(51, 'Carroll University', 'United States', '0', '/catalog/University_logo//1723022165-Carroll%20University_Favicon.png', 'Waukesha, Wisconsin', 'Carroll University is a private liberal arts university and the first four-year institution of higher learning in Wisconsin, grounded in a broad liberal arts tradition and recognized for programs in health sciences, business, psychology, biology, and more. The university emphasizes personalized attention with small class sizes, hands-on learning, and career-focused experiences.', 'https://www.carrollu.edu', '#3854 in the world by EduRank', '1846', '3,138'),
(52, 'CEG', 'united kingdom', '/catalog/University_Banner/cambridge education group    banner.png', '/catalog/University_Favicon/cambridge educationgroup   faviconFavicon.png', 'United Kingdom', 'Cambridge Education Group (CEG) is an international education provider offering pathway and academic programs.', 'https://www.ceg-uk.com', 'Not applicable', '1952', ''),
(53, 'Central Methodist University', 'United States', '0', '0', 'Fayette, Missouri, USA', 'Central Methodist University is a private liberal arts university offering undergraduate and graduate programs.', 'https://www.centralmethodist.edu', 'Not ranked globally', '1854', '4000'),
(54, 'Central Queensland University', 'Australia', '/catalog/University_Banner/Australia/CentralQueenslandUniversitybanner.png', '/catalog/University_Favicon/australia/Central Queensland University_Favicon.png', 'Rockhampton, Queensland, Australia', 'Central Queensland University is a public university known for applied research and strong regional presence.', 'https://www.cqu.edu.au', '601?650 (QS)', '1967', '30000'),
(55, 'Charleston Southern University', 'United States', '0', '/catalog/University_Favicon/usa/Charleston Southern University_Favicon.png', 'Charleston, South Carolina, USA', 'Charleston Southern University is a private Christian university known for its strong undergraduate programs and active campus life. It offers degrees in business, education, sciences, and arts with a focus on character development and service learning. The university fosters leadership skills and practical experience through internships and community engagement.', 'https://www.charlestonsouthern.edu', 'Not in major world rankings', '1960', '3,500'),
(56, 'City University of London', 'united kingdom', '/catalog/University_Banner/City University of London-Banner.png', '/catalog/University_Favicon/City University of London_Favicon.png', 'London, England', 'City, University of London is a public research university founded in 1894 (originating as the Northampton Institute) and became a university by royal charter in 1966; it joined the University of London in 2016. It offers a wide range of undergraduate and postgraduate programs with strong links to business, law, journalism, health sciences, and technology, and a focus on professional practice, industry connections, and global engagement.', 'https://www.city.ac.uk', 'QS World University Rankings 2026: ~#310 globally', '1836', '14067'),
(57, 'Cleveland State University', 'United States', '0', '/catalog/University_Favicon/usa/Cleveland State University_Favicon.png', 'Cleveland, Ohio', 'Cleveland State University is a public research university located in the heart of downtown Cleveland. It offers more than 200 academic programs across undergraduate, graduate, and doctoral levels. The university is known for applied research, strong industry partnerships, and community engagement in business, engineering, health sciences, and urban affairs.', 'https://www.csuohio.edu', '#851 in the world by QS World University Rankings', '1964', '14,160'),
(58, 'Colby-Sawyer College', 'United States', '0', '0', 'New London, New Hampshire', 'Colby-Sawyer College is a private liberal arts college located in New London, New Hampshire, USA, offering undergraduate and selected graduate programs with a strong focus on personalized education, internships, and student-centered learning. Founded in 1837, it features small class sizes and close faculty-student interaction in a scenic rural campus setting. The college emphasizes practical experience and community engagement through hands-on learning and capstone projects.', 'https://www.colby-sawyer.edu', '#5051 globally in the EduRank World University Rankings', '1837', '950'),
(59, 'College of the Rockies', 'Canada', '/catalog/University_Banner/canada-banner/College of the Rockies    banner.png', '/catalog/University_Favicon/canada/College of the Rockies Favicon.png', 'Cranbrook, British Columbia, Canada', 'College of the Rockies is a public college offering certificates, diplomas, and university transfer programs. It focuses on trades, health, business, and tourism-related education. The college emphasizes hands-on training, small class sizes, and strong ties to regional employers.', 'https://www.cotr.bc.ca', 'Not ranked (college, not university)', '1975', '4000'),
(60, 'Colorado Mesa University', 'United States', '0', '0', 'Grand Junction, Colorado', 'Colorado Mesa University (CMU) is a public university in Grand Junction, Colorado, USA, offering more than 100 undergraduate and 11 graduate programs across liberal arts, professional, and technical fields. Founded in 1925, the university emphasizes affordable, career-aligned education and serves a diverse student body with a focus on community impact and experiential learning. CMU?s campus is set in a scenic western Colorado location with strong outdoor and athletic traditions.', 'https://www.coloradomesa.edu/', '#3060 in the world EduRank', '1925', '9591'),
(61, 'Colorado State University', 'United States', '0', '/catalog/University_Favicon/usa/Colorado State University at Fort Collins_Favicon.png', 'Fort Collins, Colorado', 'Colorado State University (CSU) is a major public research university in Fort Collins, Colorado, USA, known for its strong academic programs, research activity and commitment to sustainability and community engagement. Founded in 1870 as the state?s land-grant institution, CSU offers a wide range of undergraduate, graduate and professional degrees. The university emphasizes hands-on learning, global impact and innovative solutions to real-world problems. It also has campuses and programs across Colorado and internationally.', 'https://www.colostate.edu', '#458 globally (QS World University Rankings)', '1870', '34,218'),
(62, 'Concordia University, Chicago', 'United States', '0', '/catalog/University_logo//1723210317-Concordia%20University-%20Chicago_Favicon.png', 'River Forest, Illinois, USA', 'Concordia University Chicago is a private Lutheran university offering 100+ undergraduate and graduate programs. It began as a teachers? seminary and now emphasizes liberal arts, business, science, education and health professions. The university blends faith-based values with practical education and community involvement.', 'https://www.cuchicago.edu', 'Not ranked in major global lists', '1864', '6,205'),
(63, 'Conestoga College', 'Canada', '/catalog/University_Banner/canada-banner/Conestoga College   banner.png', '/catalog/University_Favicon/canada/Conestoga College Favicon.png', 'Kitchener, Ontario', 'Conestoga College Institute of Technology and Advanced Learning is a public polytechnic college located in Kitchener, Ontario, Canada. It offers a wide range of career-focused programs including applied degrees, diplomas, certificates, and co-operative education across fields like business, engineering, health sciences, technology, and trades. Conestoga is known for its hands-on learning, strong industry partnerships, and applied research initiatives across multiple campuses.', 'https://www.conestogac.on.ca', '#5930 (Webometrics global)', '1967', '55000'),
(64, 'Cornish College of the Arts', 'United States', '0', '0', 'Seattle, Washington, USA', 'Cornish College of the Arts is a private arts college focused on music, dance, theater, and visual arts.', 'https://www.cornish.edu', 'Not ranked globally', '1914', '800'),
(65, 'Coventry University', 'united kingdom', '/catalog/University_Banner/Coventry University Banner.jpg', '/catalog/University_Favicon/Coventry University_Favicon.png', 'Coventry, England', 'Coventry University is a modern public research university known for high-quality teaching, applied research, industry connections, and a strong global outlook. It offers a wide range of undergraduate and postgraduate programs across arts, engineering, business, health, science, and more, and focuses on employability and real-world experience.', 'https://www.coventry.ac.uk', '#531 in the world by QS World University Rankings', '1843', '38,000'),
(66, 'Cranfield University', 'united kingdom', '/catalog/University_Banner/Cranfield University  Banner (1).png', '/catalog/University_Favicon/CranfieldUniversityFavicon.png', 'Cranfield, England, UK', 'Cranfield University is a specialist postgraduate-only public university focused on science, engineering, technology, and management. It is highly regarded for industry-led education, research impact, and professional development. The university works closely with government, defense, and global industries.', 'https://www.cranfield.ac.uk', '#801?1000 in the world by QS World University Rankings', '1946', '4500'),
(67, 'Curtin Singapore', 'singapore', '0', '/catalog/University_logo//1723019018-Curtin%20Singapore_Favicon.png', 'Singapore', 'Curtin University Singapore is a branch campus of Curtin University offering Australian degrees.', 'https://www.curtin.edu.sg', 'Top 200 (QS ? parent university)', '2008', '3000'),
(68, 'Dakota Wesleyan University', 'United States', '0', '0', 'Mitchell, South Dakota', 'Dakota Wesleyan University (DWU) is a private Methodist university affiliated with the United Methodist Church. It offers undergraduate and graduate programs with a focus on liberal arts, sciences, education, business, and allied health, emphasizing personalized attention and service rooted in its Christian mission. The campus, established in the late 19th century, is listed on the National Register of Historic Places.', 'https://www.dwu.edu', '#6300 in the world by EduRank', '1885', '892'),
(69, 'De Montfort University', 'united kingdom', '/catalog/University_Banner/De Montfort University-banner.png', '/catalog/University_Favicon/DeMontfortUniversityFavicon.png', 'Leicester, England', 'De Montfort University (DMU) is a public university located in Leicester, England, UK, with roots dating back to 1870. It offers a wide range of undergraduate and postgraduate programs across arts, design, business, health sciences, technology, and more, and is known for its practical, career-focused education and vibrant international community. The university emphasizes student experience, industry links, and opportunities like work experience and global mobility programs.', 'https://www.dmu.ac.uk/home.aspx', '#801 in the world by QS World University Rankings', '1969', '17131'),
(70, 'De Montfort University Dubai', 'united arab emirates', '0', '/catalog/University_Favicon/dubai/De Montfort University Dubai_Favicon.png', 'Dubai, United Arab Emirates', 'De Montfort University Dubai is the international branch campus of De Montfort University UK. It offers career-oriented undergraduate and postgraduate programs in business, law, computing, and media. The campus emphasizes global education, industry relevance, and UK-standard teaching in Dubai.', 'https://www.dmu.ac.uk/dubai', 'Not ranked separately (parent university ranked globally)', '2017', '3000'),
(71, 'De Montfort University London', '', '/catalog/University_Banner//1740205743-De-Montfort-University-banner.png', '/catalog/University_logo//1740205743-DeMontfortUniversityFavicon.png', 'London, England, UK', 'De Montfort University London delivers business and management programs from De Montfort University Leicester.', 'https://www.dmu.ac.uk', 'Top 800 (QS)', '1870', '1500'),
(72, 'Dean College', 'United States', '0', '0', 'Franklin County, Massachusetts', 'Dean College is a private residential college located in Franklin, Massachusetts, USA, offering associate and bachelor?s degree programs with a strong emphasis on personalized education, experiential learning, and career preparation. Founded in 1865, Dean has a long tradition of close student?faculty engagement, a vibrant campus community, and recognition for hands-on learning and student success.', 'https://www.dean.edu', '#3,198 globally (EduRank 2025)', '1865', '1301'),
(73, 'DePaul University', 'United States', '0', '/catalog/University_Favicon/usa/DePaul University_Favicon.png', 'Chicago, Illinois', 'DePaul University is a private Catholic research university founded in 1898, named after Saint Vincent de Paul. It offers a wide range of undergraduate, graduate, and professional programs across arts, sciences, business, education, law, computing, and more, with strong ties to the city?s industries and diverse community.', 'https://www.depaul.edu', '#646 in the world by EduRank', '1898', '21,348'),
(74, 'DeVry University', 'United States', '0', '/catalog/University_logo//1723210367-DeVry%20University_Favicon.png', 'Naperville, Illinois, USA', 'DeVry University is a private university specializing in business, technology, and online education.', 'https://www.devry.edu', 'Not ranked globally', '1931', '20000'),
(75, 'Drew University', 'United States', '0', '/catalog/University_logo//1723263938-Drew%20University_Favicon.png', 'Madison, New Jersey', 'Drew University is a private liberal arts university founded in 1867, historically affiliated with the United Methodist Church. It offers a wide range of undergraduate and graduate programs with an emphasis on liberal arts, sciences, research, experiential learning (including New York City semester programs), and global education opportunities. The campus, known as ?The Forest,? spans approximately 186 acres of wooded land.', 'https://www.drew.edu', '#2251 in the world by EduRank', '1867', '2,200'),
(76, 'Dubai Enquiry', 'united arab emirates', '0', '/catalog/University_Favicon/ireland/Enquiry_Favicon.png', 'Dubai, United Arab Emirates', 'Dubai Enquiry is an education advisory service assisting students with admissions in UAE institutions.', 'Not applicable', 'Not applicable', 'Not applicable', ''),
(77, 'Dublin Business School', 'Ireland', '/catalog/University_Banner/Ireland/DublinBusinessSchoolbanner.png', '/catalog/University_logo//1726291339-Dublin-Business-School_Favicon.png', 'Dublin, Ireland', 'Dublin Business School is a private higher education institution specializing in business, finance, law, computing, and media. It offers undergraduate and postgraduate programs with a strong focus on practical skills and career readiness. The institution emphasizes industry relevance, professional qualifications, and flexible learning. It attracts a diverse international student population.', 'https://www.dbs.ie', 'Not ranked globally', '1975', '9000'),
(78, 'Dublin City University', 'Ireland', '/catalog/University_Banner/Ireland/DublinCityUniversitybanner.png', '/catalog/University_Favicon/ireland/Dublin City University_Favicon.png', 'Dublin, Ireland', 'Dublin City University is a public research university known for innovation, business, and engineering programs.', 'https://www.dcu.ie', 'Top 400 (QS)', '1980', '17000'),
(79, 'Dundalk Institute of Technology', 'Ireland', '/catalog/University_Banner/Ireland/DundalkInstituteofTechnologybanner.png', '/catalog/University_Favicon/ireland/Dundalk Institute of Technology_Favicon.png', 'Dundalk, Louth', 'Dundalk Institute of Technology (DkIT) is a public institute of technology located in Dundalk, County Louth, Ireland. It offers a range of undergraduate and postgraduate programmes with a focus on practical, career-oriented education, research, and strong industry links. DkIT has a diverse student body and provides students with opportunities in fields like business, engineering, computing, and health sciences.', 'https://www.dkit.ie', '~#3310 globally (EduRank 2025)', '1970', '5000'),
(80, 'Duquesne University', 'United States', '0', '/catalog/University_Favicon/usa/Duquesne University_Favicon.png', 'Pittsburgh, Pennsylvania, USA', 'Duquesne University is a private Catholic research university known for health sciences, business, and liberal arts.', 'https://www.duq.edu', 'Top 650 (QS)', '1878', '9500'),
(81, 'Durham College', 'Canada', '/catalog/University_Banner/canada-banner/Durham College  banner.png', '/catalog/University_Favicon/canada/Durham college Favicon.png', 'Oshawa, Ontario', 'Durham College of Applied Arts and Technology is a public college located in Oshawa and Whitby, Ontario, Canada. It offers more than 140 programs including diplomas, advanced diplomas, bachelor?s degrees, and apprenticeship programs focused on hands-on learning, co-op placements, field experience, and applied research. The college emphasizes industry-relevant skills and career readiness in fields like business, health, technology, engineering, media, and trades.', 'https://www.durhamcollege.ca', '#7605 (Webometrics 2025)', '1967', '30000'),
(82, 'Durham University', 'united kingdom', '/catalog/University_Banner/Durham University London Banner.png', '/catalog/University_Favicon/DurhamUniversityFavicon.png', 'Durham, England, UK', 'Durham University is a prestigious collegiate public research university and a member of the Russell Group.', 'https://www.durham.ac.uk', 'Top 100 (QS)', '1832', '20000'),
(83, 'Edgewood College', 'United States', '0', '0', 'Madison, Wisconsin', 'Edgewood College is a private Catholic liberal arts institution in Madison, Wisconsin, USA, founded in 1927 and rooted in Dominican Catholic values. It offers a range of undergraduate and graduate programs with an emphasis on personalized teaching, community, and career preparation. The college provides a supportive campus environment close to downtown Madison and balances liberal arts education with professional pathways.', 'https://www.edgewood.edu', '#4511 globally in the EduRank World University Rankings', '1927', '2,459'),
(84, 'Edinburgh Napier University', 'united kingdom', '/catalog/University_Banner/Edinburgh Napier University-banner.png', '/catalog/University_Favicon/Edinburgh Napier UniversityFavicon.png', 'Edinburgh, Scotland, UK', 'Edinburgh Napier University is a modern public university known for applied teaching and research excellence. It offers programs in engineering, computing, business, health, and creative industries. The university emphasizes innovation, employability, and strong industry engagement. It operates multiple campuses across Edinburgh.', 'https://www.napier.ac.uk', '801?1000 (QS)', '1964', '19500'),
(85, 'Enquiry Malaysia', 'Malaysia', '0', '0', 'Malaysia', 'Malaysia Enquiry is an education advisory service focused on Malaysian universities and institutions.', 'Not applicable', 'Not applicable', 'Not applicable', ''),
(86, 'Eureka College', 'United States', '0', '0', 'Eureka, USA', 'Eureka College is a private liberal arts college in Eureka, Illinois, United States, founded by abolitionists and historically committed to inclusive education. It was among the first U.S. colleges to admit men and women equally and maintains a close-knit campus community with personalized learning. The college is also known for its association with U.S. President Ronald Reagan, an alumnus.', 'https://www.eureka.edu', '#5540 in the world (EduRank global ranking)', '1855', '559'),
(87, 'Fairfield University', 'United States', '0', '0', 'Fairfield, Connecticut', 'Fairfield University is a private Jesuit Catholic university located in Fairfield, Connecticut, USA, offering undergraduate and graduate programs across arts, sciences, business, nursing, engineering, and more. It emphasizes holistic education, experiential learning, and global engagement, with strong career outcomes for graduates. The campus supports a vibrant community with study abroad opportunities and professional preparation.', 'https://www.fairfield.edu/', '#251 in the world by QS World University Ranking', '1942', '5192'),
(88, 'Fairleigh Dickinson University', 'United States', '0', '/catalog/University_Favicon/usa/Fairleigh Dickinson University_Favicon.png', 'Teaneck & Madison, New Jersey', 'Fairleigh Dickinson University is a private university with multiple campuses in the United States and abroad. It offers a wide range of undergraduate and graduate programs in business, engineering, health sciences, and international studies. The university emphasizes global education, professional development, and experiential learning.', 'https://www.fdu.edu', '#3001?3500 in the world by EduRank', '1942', '12000'),
(89, 'Fanshawe College of Applied Arts and Technology', 'Canada', '/catalog/University_Banner/canada-banner/Fanshawe College of Applied Arts and Technology  banner.png', '/catalog/University_Favicon/canada/Fanshawe College Favicon.png', 'London, Ontario, Canada', 'Fanshawe College of Applied Arts and Technology is a public college offering career-focused diploma, degree, and postgraduate programs. It is known for applied learning, industry partnerships, and strong employability outcomes. The college serves a large and diverse student population with modern facilities.', 'https://www.fanshawec.ca', 'Not ranked (college, not university)', '1967', '43000'),
(90, 'Fisher College', 'United States', '0', '/catalog/University_logo//1723020468-Fisher%20College_Favicon.png', 'Boston, Massachusetts', 'Fisher College is a private nonprofit college located in Boston, Massachusetts, USA, offering associate?s, bachelor\'s, and master?s programs with a focus on career-oriented education and urban campus experience. Founded in 1903, it provides flexible learning formats and close student-faculty interaction through small class sizes. Fisher?s programs span business, health care, human services, psychology, and criminal justice, among others.', 'https://www.fisher.edu', '#4,346 globally (EduRank 2025)', '1903', '1923'),
(91, 'Florida Atlantic University', 'United States', '0', '/catalog/University_Favicon/usa/Florida Atlantic University_Favicon.png', 'Boca Raton & Davie, Florida, USA', 'Florida Atlantic University (FAU) is a large public research university with comprehensive degree offerings. Its strengths include business, engineering, nursing, and oceanography. FAU emphasizes research, innovation, and community engagement, with multiple campuses serving a diverse student population.', 'https://www.fau.edu', '#1001?1200 in the world by QS World University Rankings', '1961', '30000'),
(92, 'Florida International University', 'United States', '0', '/catalog/University_Favicon/usa/Florida International University_Favicon.png', 'Miami, Florida, USA', 'Florida International University is a major public research university with strong programs in business, engineering, and hospitality.', 'https://www.fiu.edu', 'Top 600 (QS)', '1965', '56000');
INSERT INTO `university` (`id`, `name`, `country`, `banner_image`, `logo_image`, `city`, `description`, `link`, `ranking`, `established_year`, `enroll_students`) VALUES
(93, 'Gannon University', 'United States', '0', '/catalog/University_Favicon/usa/Gannon University_Favicon.png', 'Erie, Pennsylvania', 'Gannon University is a private Catholic university established in 1925 with campuses in Erie, Pennsylvania and Ruskin, Florida, USA. It offers a broad range of undergraduate, graduate, and doctoral programs emphasizing liberal arts, professional education, and hands-on learning. The university fosters values-centered education grounded in faith, leadership, and community service. Gannon has about 4,600 students and a strong focus on career-oriented academic programs.', 'https://www.gannon.edu', '#3013 globally (EduRank)', '1925', '4149'),
(94, 'George Brown College', 'Canada', '/catalog/University_Banner/canada-banner/George Brown College banner.png', '/catalog/University_Favicon/canada/George Brown College Favicon.png', 'Toronto, Ontario', 'George Brown College (recently rebranded as George Brown Polytechnic) is a public college of applied arts and technology in Toronto, Ontario, Canada. It offers hands-on programs in business, health sciences, arts, construction, hospitality, community services and more, with strong ties to industry and experiential learning. Founded in 1967, it serves tens of thousands of students across multiple downtown campuses and is known for practical, career-oriented education.', 'https://www.georgebrown.ca', '#5584 globally according to the Webometrics World University Ranking', '1967', '30,000'),
(95, 'George Mason University', 'United States', '0', '/catalog/University_logo//1723210456-George%20Mason%20University_Favicon.png', 'Fairfax, Virginia, USA', 'George Mason University is a large public research university known for innovation and interdisciplinary studies. It offers strong programs in business, public policy, engineering, law, and computer science. The university emphasizes research, entrepreneurship, and partnerships with government and industry.', 'https://www.gmu.edu', '#501?550 in the world by QS World University Rankings', '1972', '39000'),
(96, 'Georgian College', 'Canada', '/catalog/University_Banner/canada-banner/Georgian College banner.png', '/catalog/University_Favicon/canada/Georgian College Favicon.png', 'Barrie, Ontario, Canada', 'Georgian College is a public college known for applied learning and strong co-op education programs. It offers diplomas, degrees, and postgraduate certificates in business, health, engineering technology, and hospitality. The college emphasizes career readiness, industry partnerships, and experiential education.', 'https://www.georgiancollege.ca', 'Not ranked (college, not university)', '1967', '13000'),
(97, 'Glasgow Caledonian University', 'united kingdom', '/catalog/University_Banner/Glasgow Caledonian University.png', '/catalog/University_Favicon/Glasgow Caledonian UniversityFavicon.png', 'Glasgow, Scotland', 'Glasgow Caledonian University (GCU) is a public university located in Glasgow, Scotland, UK, known for its strong industry links, emphasis on employability, and values-led education. It offers a wide range of undergraduate, postgraduate and research programmes with a focus on practical learning and global impact. GCU has a diverse student community and modern campus facilities in the city centre.', 'https://www.gcu.ac.uk', '#926 globally according to the Webometrics World University Rankings', '1993', '23,000'),
(98, 'Goldsmiths University of London', 'united kingdom', '/catalog/University_Banner/Goldsmiths University of London Banner.png', '/catalog/University_Favicon/GoldsmithsUniversityofLondonFavicon.png', 'London, England, UK', 'Goldsmiths, University of London is a public research university known for creativity and critical thinking. It specializes in arts, humanities, social sciences, media, and computing. The university is internationally recognized for sociology, arts, and cultural studies. It emphasizes innovative teaching, research impact, and social engagement.', 'https://www.gold.ac.uk', '601?650 (QS)', '1891', '10000'),
(99, 'Gonzaga University', 'United States', '0', '/catalog/University_logo//1723210515-Gonzaga%20University_Favicon.png', 'Spokane, Washington, USA', 'Gonzaga University is a private Jesuit university known for business, law, and strong liberal arts education.', 'https://www.gonzaga.edu', 'Top 1000 (QS)', '1887', '7500'),
(100, 'Great Plain College', 'Canada', '/catalog/University_Banner/canada-banner/Great Plains College banner.png', '/catalog/University_Favicon/canada/great plains_favicon.png', 'Swift Current, Saskatchewan, Canada', 'Great Plains College is a regional college offering certificates, diplomas, and university transfer programs. It focuses on practical, skills-based education aligned with regional workforce needs. The college emphasizes accessibility, community engagement, and flexible learning pathways.', 'https://www.greatplainscollege.ca', 'Not ranked (college, not university)', '2008', '1500'),
(101, 'Griffith College, Ireland', 'Ireland', '/catalog/University_Banner/Ireland/GriffithCollegeDublinbanner.png', '/catalog/University_Favicon/ireland/Griffith College Dublin_Favicon.png', 'Dublin, Ireland', 'Griffith College is a private higher education institution known for business, computing, law, and media programs.', 'https://www.griffith.ie', 'Not ranked globally', '1974', '7000'),
(102, 'Hanover College', 'United States', '0', '0', 'Hanover, Indiana, USA', 'Hanover College is a private liberal arts college known for its strong undergraduate education and personalized learning environment. It emphasizes critical thinking, interdisciplinary study, and close faculty-student relationships. The college offers programs in arts, sciences, business, and pre-professional studies.', 'https://www.hanover.edu', 'Not ranked in major global rankings', '1827', '1100'),
(103, 'Hartwick College', 'United States', '0', '0', 'Oneonta, New York', 'Hartwick College is a private liberal arts college focused on personalized education and small class sizes. It emphasizes interdisciplinary learning, critical thinking, and hands-on academic experiences. The college offers a strong undergraduate curriculum with opportunities for research, internships, and global study programs.', 'https://www.hartwick.edu', '#501?600 in the United States by U.S. News', '1797', '1,114'),
(104, 'Heriot Watt University UK', 'united kingdom', '/catalog/University_Banner/Heriot Watt University-banner.png', '/catalog/University_Favicon/Heriot Watt UniversityUKFavicon.png', 'Edinburgh, Scotland', 'Heriot-Watt University is a public research university established in 1821 and granted university status by Royal Charter in 1966. It is one of the oldest higher education institutions in the UK, originally founded as the School of Arts of Edinburgh and named after Scottish innovator James Watt and philanthropist George Heriot. The university is known for strong STEM, engineering, business and applied sciences programs, an international outlook, and a focus on industry-relevant education. Heriot-Watt has multiple campuses ? including in Edinburgh, the Scottish Borders, Orkney, Dubai (UAE) and Malaysia ? and serves a diverse global student body.', 'https://www.hw.ac.uk', '#287 by QS World University Rankings 2026', '1821', '27,000'),
(105, 'Heriot-Watt University - Malaysia', 'Malaysia', '0', '0', 'Putrajaya, Malaysia', 'Heriot-Watt University Malaysia is a branch campus of Heriot-Watt University specializing in engineering and business.', 'https://www.hw.ac.uk/malaysia', 'Top 300 (QS)', '2014', '3500'),
(106, 'Heriot-Watt University Dubai', 'united arab emirates', '0', '/catalog/University_Favicon/dubai/Heriot-Watt University_Favicon.png', 'Dubai, United Arab Emirates', 'Heriot-Watt University Dubai is the international campus of Heriot-Watt University UK. It offers UK-accredited undergraduate and postgraduate programs in engineering, business, data science, and built environment. The campus is known for strong industry links, research-led teaching, and global employability.', 'https://www.hw.ac.uk/dubai', 'Parent university #256 in the world by QS', '2005 (Dubai campus)', '4000'),
(107, 'Herzing University', 'United States', '0', '0', 'Milwaukee, Wisconsin, USA', 'Herzing University is a private, career-focused university based in the United States, offering undergraduate and graduate programs in healthcare, business, technology, and public safety. It is known for flexible learning options, including online and campus-based programs designed for working professionals. The university emphasizes practical skills, career readiness, and industry-aligned education to support student employment outcomes.', 'https://www.herzing.edu/', '#6000 in the world by EduRank', '1965', '5,274'),
(108, 'Hiram College', 'United States', '0', '0', 'Hiram, Ohio, USA', 'Hiram College is a private liberal arts college offering undergraduate programs with a strong emphasis on personalized education. It focuses on critical thinking, interdisciplinary learning, and close faculty-student interaction. The college promotes leadership, research, and experiential learning opportunities.', 'https://www.hiram.edu', 'Not ranked in major global rankings', '1850', '1100'),
(109, 'Hofstra University', 'United States', '0', '/catalog/University_logo//1723020533-Hofstra%20University_Favicon.png', 'Hempstead, New York', 'Hofstra University is a private research university located in Hempstead, New York, USA, on Long Island, about 25 miles from New York City. Founded in 1935, it offers undergraduate and graduate programs across arts, sciences, business, engineering, law, and medicine, with an emphasis on experiential learning, research, and professional preparation. Hofstra is nationally recognized for hosting multiple U.S. presidential debates and for its strong academic community and campus life.', 'https://www.hofstra.edu', 'Webometrics World Ranking (July 2025): ~#631 globally', '1935', '11131'),
(110, 'Hult Business School - London', 'united kingdom', '0', '/catalog/University_logo/Hult Business School.jpg', 'London, England, UK', 'Hult International Business School ? London Campus specializes in global business and MBA programs.', 'https://www.hult.edu', 'Not ranked globally', '1964', '6000'),
(111, 'Hult Business School - USA', 'United States', '0', '/catalog/University_logo//1723210617-Hult%20International%20Business%20School_Favicon.png', 'Boston & San Francisco, USA', 'Hult International Business School ? USA campuses focus on international business and entrepreneurship.', 'https://www.hult.edu', 'Not ranked globally', '1964', '6000'),
(112, 'Illinois State University', 'United States', '0', '/catalog/University_logo//1723020407-Illinois%20State%20University_Favicon.png', 'Normal, Illinois', 'Illinois State University is a public research university and the oldest public institution of higher education in Illinois. It offers a wide range of undergraduate, graduate, and doctoral programs across arts and sciences, business, education, nursing, fine arts, and more, with strong emphasis on teacher preparation, research, and community engagement.', 'https://www.illinoisstate.edu', '#1789 in the world by CWUR', '1857', '21,994'),
(113, 'INTO - UK', 'united kingdom', '0', '/catalog/University_Favicon/INTOFavicon.png', 'United Kingdom', 'INTO UK offers international foundation and pathway programs in partnership with UK universities.', 'https://www.intostudy.com', 'Not applicable', '2005', ''),
(114, 'James Madison University', 'United States', '0', '/catalog/University_Favicon/usa/James Madison University_Favicon.png', 'Harrisonburg, Virginia', 'James Madison University (JMU) is a public research university located in Harrisonburg, Virginia, USA. Founded in 1908, it offers a wide range of undergraduate, graduate, and doctoral programs across arts, sciences, business, engineering, and health disciplines. JMU is known for its strong teaching quality, vibrant campus life, and commitment to student success, blending academic rigor with real-world opportunities.', 'https://www.jmu.edu/index.shtml', '#888 in the world by EduRank', '1908', '21836'),
(115, 'Jessup University', 'United States', '0', '/catalog/University_Favicon/usa/Jessup University_Favicon.png', 'Rocklin, California, USA', 'Jessup University is a private Christian university offering programs in business, education, and liberal arts.', 'https://www.jessup.edu', 'Not ranked globally', '1939', '1700'),
(116, 'Johns Hopkins University', 'United States', '0', '0', 'Baltimore, Maryland, USA', 'Johns Hopkins University is a world-renowned private research university known for excellence in medicine, public health, engineering, and sciences. It is a global leader in research output and innovation. The university emphasizes interdisciplinary collaboration, global impact, and academic excellence.', 'https://www.jhu.edu', '#28 in the world by QS World University Rankings', '1876', '29000'),
(117, 'Keele University', 'united kingdom', '0', '/catalog/University_logo//1741243377-Keele-University_Favicon.png', 'Keele, England, UK', 'Keele University is a public research university noted for its strong interdisciplinary approach and liberal arts foundation. It offers a broad range of undergraduate and postgraduate degrees and emphasizes small class sizes and student engagement. Keele also has a large campus with strong community and research links.', 'https://www.keele.ac.uk', '#601?650 in the world by THE World University Rankings', '1949', '11,000'),
(118, 'Kent State University', 'United States', '0', '/catalog/University_Favicon/usa/Kent State University_Favicon.png', 'Kent, Ohio, USA', 'Kent State University is a public research university with a large and diverse academic portfolio, including arts, sciences, business, and engineering. Known for strong research output and community engagement, it offers over 300 degree programs and supports global study and experiential learning.', 'https://www.kent.edu', 'Ranked in global lists (varies by source)', '1910', '41,697'),
(119, 'Kings College London', 'united kingdom', '/catalog/University_Banner/Kings College London Banner (1).png', '/catalog/University_Favicon/Kings College LondonFavicon.png', 'London, England', 'King?s College London is a leading public research university and a member of the prestigious University of London. It is internationally recognized for excellence in research, teaching, and innovation across fields such as medicine, law, humanities, social sciences, and international relations. The university has a strong global reputation and attracts students from all over the world.', 'https://www.kcl.ac.uk', '#31 in the world by QS World University Rankings', '1829', '42,000'),
(120, 'Kingston University', 'united kingdom', '/catalog/University_Banner/Kingston University _Banner.png', '/catalog/University_Favicon/Kingston UniversityFavicon.png', 'Kingston upon Thames, London', 'Kingston University is a public research university located in Kingston upon Thames, London, England, UK. With roots dating back to the Kingston Technical Institute (1899) and full university status in 1992, it offers a variety of undergraduate, postgraduate, and research programmes across arts, business, science, engineering and health disciplines. The university is known for practical, industry-connected education, creative programmes, and a diverse student community from over 140 countries.', 'https://www.kingston.ac.uk', '#1776 globally in the CWUR World University Rankings', '1992', '19,411'),
(121, 'La Trobe University ', 'Australia', '/catalog/University_Banner/Australia/LaTrobeUniversity banner.png', '/catalog/University_Favicon/australia/La Trobe University_Favicon.png', 'Melbourne, Victoria, Australia', 'La Trobe University is a public research university with a strong international reputation. It offers a wide range of undergraduate and postgraduate programs with strengths in health sciences, business, education, and humanities. The university emphasizes research excellence, innovation, and global engagement.', 'https://www.latrobe.edu.au', '#242 in the world by QS World University Rankings', '1964', '38000'),
(122, 'Lakehead University', 'Canada', '/catalog/University_Banner/canada-banner/Lakehead University  banner.png', '/catalog/University_Favicon/canada/Lakehead University Favicon.png', 'Thunder Bay & Orillia, Ontario, Canada', 'Lakehead University is a public university known for engineering, health sciences, and environmental studies.', 'https://www.lakeheadu.ca', 'Not ranked globally', '1965', '8500'),
(123, 'Lakeland University', 'United States', '0', '0', 'Plymouth, Wisconsin', 'Lakeland University is a private university located in Plymouth (Sheboygan County), Wisconsin, United States. Founded in 1862 and affiliated with the United Church of Christ, the university offers bachelor?s and master?s degree programs with a strong emphasis on experiential learning, Cooperative Education, and flexible delivery formats (including evening, weekend, and online). It serves students across its Wisconsin centers and an international campus in Tokyo, Japan.', 'https://www.lakeland.edu', '#5544 globally (EduRank 2025)', '1862', '2,786'),
(124, 'Lambton College', 'Canada', '/catalog/University_Banner/canada-banner/Lambton College  banner.png', '/catalog/University_Favicon/canada/Lambton College Favicon.png', 'Sarnia, Ontario, Canada', 'Lambton College is a public college known for applied education and technology-driven programs. It offers diplomas, degrees, and postgraduate certificates in business, IT, engineering, and health sciences. The college emphasizes practical training, co-op opportunities, and strong employer connections.', 'https://www.lambtoncollege.ca', 'Not ranked (college, not university)', '1966', '9000'),
(125, 'Lancaster University', 'united kingdom', '0', '/catalog/University_Favicon/Lancaster University_Favicon.png', 'Lancaster, England, UK', 'Lancaster University is a top UK public research university known for high academic standards and collegiate system. It excels in teaching quality and research across business, sciences, arts, and social sciences. The university consistently ranks highly for student satisfaction and global reputation.', 'https://www.lancaster.ac.uk', '#122 in the world by QS World University Rankings', '1964', '15000'),
(126, 'LaSalle College, Montreal', 'Canada', '/catalog/University_Banner/canada-banner/LaSalle College, Montreal  banner.png', '/catalog/University_Favicon/canada/LaSalleCollegeMontrealFavicon.png', 'Montreal, Quebec', 'LaSalle College is a private, bilingual post-secondary college offering vocational, pre-university, and professional programs in areas like fashion, arts & design, business, hospitality & tourism, technology, and more. It is part of the LCI Education network and is known for hands-on learning and industry-oriented training.', 'https://lasallecollege.lcieducation.com', '#8378 (Webometrics)', '1959', '17,000'),
(127, 'LaSalle College, Vancouver', 'Canada', '0', '/catalog/University_Favicon/canada/LaSalleCollegevancouverFavicon.png', 'Vancouver, British Columbia', 'LaSalle College Vancouver (LCV) is a private arts, design, media, and creative technology college in Vancouver, British Columbia, Canada. It offers bachelor?s degrees, diplomas, and certificates in fields such as fashion, graphic design, game design & VFX, culinary arts, interior design, audio & film, and more. LaSalle is part of the LCI Education network of creative institutions around the world, emphasizing hands-on, industry-focused learning and preparing students for creative careers.', 'https://www.lasallecollegevancouver.com', 'Webometrics: ~#12,161 globally', '1998', '1530'),
(128, 'Lawrence Technological University', 'United States', '0', '/catalog/University_Favicon/usa/Lawrence Technological University_Favicon.png', 'Southfield, Michigan, USA', 'Lawrence Technological University is a private university focused on STEM, architecture, and business education. It emphasizes project-based learning, innovation, and close industry collaboration. The university prepares students for professional practice through hands-on experience, internships, and applied research.', 'https://www.ltu.edu', 'Not ranked in major global rankings', '1932', '3000'),
(129, 'Leeds Beckett University', 'united kingdom', '/catalog/University_Banner/Leads-beckett-banner.jpg', '/catalog/University_Favicon/LeedsBeckettUniversityFavicon.png', 'Leeds, England, UK', 'Leeds Beckett University is a public university offering career-oriented undergraduate and postgraduate programs. It is known for strengths in business, sports science, engineering, health, and creative industries. The university emphasizes employability, placements, and applied research. It has strong connections with regional and national employers.', 'https://www.leedsbeckett.ac.uk', '1001?1200 (THE)', '1992', '28000'),
(130, 'Leeds Trinity University', 'united kingdom', '0', '/catalog/University_Favicon/Leeds Trinity University_Favicon.png', 'Leeds, England, UK', 'Leeds Trinity University is a public university known for its strong focus on employability and professional experience. It offers undergraduate and postgraduate programs in education, business, media, sports, and social sciences. The university emphasizes work placements, small class sizes, and student support to enhance career readiness.', 'https://www.leedstrinity.ac.uk', '#1201?1500 in the world by THE World University Rankings', '1966', '3500'),
(131, 'Lewis University', 'United States', '0', '/catalog/University_logo//1723118802-Lewis%20University_Favicon.png', 'Romeoville, Illinois', 'Lewis University is a private Catholic Lasallian university known for combining a strong liberal arts foundation with career-focused, professional education. It offers more than 80 undergraduate majors and 35 graduate programs across fields such as aviation, business, nursing, education, science & technology, and criminal justice. The university emphasizes hands-on experience, small class sizes, and preparation for the workforce.', 'https://www.lewisu.edu', '#3,431 globally (EduRank 2025)', '1932', '6500'),
(132, 'Lipscomb University', 'United States', '0', '/catalog/University_logo//1723210736-Lipscomb%20University_Favicon.png', 'Nashville, Tennessee', 'Lipscomb University is a private Christian university affiliated with the Churches of Christ, offering undergraduate, graduate, and doctoral programs across liberal arts, sciences, business, engineering, education, health sciences and more, with a mission focused on academic excellence, spiritual growth, and community engagement.', 'https://www.lipscomb.edu', '#2937 in the world by EduRank', '1891', '5,017'),
(133, 'Liverpool John Moores University', 'united kingdom', '/catalog/University_Banner/Liverpool John Moores University  Banner.png', '/catalog/University_Favicon/Liverpool John Moores University_Favicon.png', 'Liverpool, England, UK', 'Liverpool John Moores University is a large public university with a strong focus on applied research and employability. It offers programs across engineering, business, health, sciences, and creative industries. The university has strong industry links and professional accreditations. It emphasizes real-world learning and innovation.', 'https://www.ljmu.ac.uk', '601?800 (THE)', '1823', '25000'),
(134, 'London Metropolitan University', 'united kingdom', '/catalog/University_Banner/London Metropolitan University  Banner.png', '/catalog/University_Favicon/London Metropolitan UniversityFavicon.png', 'London, England', 'London Metropolitan University (London Met) is a public university formed in 2002 through the merger of London Guildhall University and the University of North London (with educational roots going back to the 19th century). It offers a wide range of undergraduate and postgraduate programmes with a strong focus on career-oriented learning, professional practice, and social inclusion. London Met is known for its diverse student community and commitment to widening access to higher education.', 'https://www.londonmet.ac.uk', '#1537 globally (Webometrics 2025)', '2002', '12475'),
(135, 'Long Island University Brooklyn', 'United States', '0', '/catalog/University_Favicon/usa/Long Island University Brooklyn_Favicon.png', 'Brooklyn, New York', 'Long Island University (LIU) is a private research university founded in 1926 with multiple campuses across New York, including LIU Brooklyn ? the original and historic urban campus located in the heart of Brooklyn. LIU offers more than 500 undergraduate and graduate degree programs and emphasizes experiential learning, professional preparation, and a global mindset. The Brooklyn campus is known for its strong health sciences, pharmacy, nursing, business, arts, and liberal studies programs, as well as Division I athletics and experiential opportunities in New York City.', 'https://www.liu.edu', '#1317 in the world by EduRank', '1926', '11,200'),
(136, 'Long Island University Post', 'United States', '0', '/catalog/University_Favicon/usa/Long Island University Post_Favicon.png', 'Brookville, New York', 'LIU Post (C.W. Post Campus) is a private university campus of Long Island University, offering undergraduate and graduate programs in business, arts, sciences, education, health professions, IT and more, with Division I athletics and a vibrant campus life.', 'https://liu.edu/post', '#1317 in the world by EduRank', '1951', '16,322'),
(137, 'Loughborough University', 'united kingdom', '0', '/catalog/University_logo/Loughborough University.jpg', 'Loughborough, England, UK', 'Loughborough University is a leading public research university known globally for engineering, sports science, and design.', 'https://www.lboro.ac.uk', 'Top 250 (QS)', '1909', '18000'),
(138, 'Louisiana State University', 'United States', '0', '/catalog/University_logo//1723210925-Louisiana%20State%20University_Favicon.png', 'Baton Rouge, Louisiana', 'Louisiana State University (LSU) is a public land-grant research university in Baton Rouge, Louisiana, USA, and is the flagship institution of the LSU System. Founded in 1860, it offers a wide range of undergraduate, graduate, and professional programs with strong research activity and community engagement. LSU is known for its extensive academic offerings, vibrant campus culture, and NCAA Division I athletics.', 'https://www.lsu.edu', '#173 globally in the EduRank World University Rankings', '1860', '41,700'),
(139, 'Lycoming College', 'United States', '0', '0', 'Williamsport, Pennsylvania', 'Lycoming College is a private liberal arts college in Williamsport, Pennsylvania, USA, offering undergraduate programs in arts, sciences and professional fields with a focus on personalized education and student engagement. Founded in 1812, it features small class sizes, strong faculty interaction, and a tight-knit campus community. The college emphasizes experiential learning, internships, and career preparation.', 'https://www.lycoming.edu', '#3934 globally in the EduRank World University Rankings', '1812', '1,012'),
(140, 'Lynn University', 'United States', '0', '0', 'Boca Raton, Florida', 'Lynn University is a private university located in Boca Raton, Florida, USA, known for its personalized ?Dialogues? curriculum, strong international student community, and innovative academic approach. Founded in 1962, it offers undergraduate, graduate, and doctoral programs with a focus on practical learning and global engagement. The campus is diverse, with students from over 100 countries, and emphasizes career preparation and global experience.', 'https://www.lynn.edu', '#2414 globally in the EduRank World University Rankings', '1962', '3,500'),
(141, 'Marist College', 'United States', '0', '/catalog/University_Favicon/usa/Marist College_Favicon.png', 'Poughkeepsie, New York, USA', 'Marist College is a private institution known for strong programs in business, communications, computer science, and liberal arts. It emphasizes experiential learning, technology integration, and career preparation. The college offers a supportive campus environment with strong industry and internship connections.', 'https://www.marist.edu', 'Not ranked in major global rankings', '1929', '6500'),
(142, 'Marshall University', 'United States', '0', '/catalog/University_Favicon/usa/Marshall University_Favicon.png', 'Huntington, West Virginia', 'Marshall University is a public research university founded in 1837, named after John Marshall, the fourth Chief Justice of the United States. It is West Virginia?s second-largest university and offers a broad range of undergraduate, graduate, and professional programs across fields such as business, health sciences, engineering, liberal arts, and more. Marshall has diverse student organizations and NCAA Division I athletics (?Thundering Herd?).', 'https://www.marshall.edu', '#1137 in the world by EduRank', '1837', '13,239'),
(143, 'Maynooth University', 'Ireland', '/catalog/University_Banner/Ireland/MaynoothUniversitybanner.png', '/catalog/University_Favicon/ireland/Maynooth University_Favicon.png', 'Maynooth', 'Maynooth University is a public research university located in Maynooth, Ireland, about 25 km from Dublin. It was formally established as an autonomous university in 1997, though its origins trace back to the Royal College of St. Patrick founded in 1795. The university offers a wide range of undergraduate, postgraduate and doctoral programmes and has a diverse student body with strong research and international engagement.', 'https://www.maynoothuniversity.ie', '#1010 globally according to the EduRank World University Rankings', '1997', '16,110'),
(144, 'McMurry University', 'United States', '0', '0', 'Abilene, Texas', 'McMurry University is a private Methodist university affiliated with the United Methodist Church, known for its liberal arts and sciences education, close-knit campus community, and personalized teaching environment with a low student-to-faculty ratio. The university offers a range of undergraduate programs in fields such as business, education, nursing, arts, sciences, and pre-professional tracks, emphasizing leadership, service, and real-world readiness.', 'https://mcm.edu', '#5505 in the world by EduRank', '1923', '4,144'),
(145, 'Mercy College', 'United States', '0', '/catalog/University_Favicon/usa/Mercy College (Dobbs Ferry)_Favicon.png', 'Dobbs Ferry, New York, USA', 'Mercy College (now Mercy University) is a private nonprofit university focused on career-oriented education. It offers undergraduate and graduate programs in business, health sciences, education, psychology, and liberal arts. The university emphasizes accessibility, student support, and professional readiness.', 'https://www.mercy.edu', 'Not ranked in major global rankings', '1950', '9000'),
(146, 'Miami University', 'United States', '0', '/catalog/University_Favicon/usa/Miami University_Favicon.png', 'Oxford, Ohio', 'Miami University is a public research university and one of the oldest public universities in the United States, frequently recognized for strong undergraduate teaching, liberal arts core, and excellent student outcomes. It is sometimes classified informally as a ?Public Ivy? for offering an Ivy League?style education at a public research university price point. The university offers a broad range of undergraduate, graduate, and professional programs across disciplines such as business, engineering, education, science, arts, and more.', 'https://www.miamioh.edu', '#832 in the world by CWUR', '1809', '18,618'),
(147, 'Middlesex University', 'united kingdom', '/catalog/University_Banner/MiddlesexUniversity-banner.png', '/catalog/University_Favicon/Middlesex University London_Favicon.png', 'London, England', 'Middlesex University is a public research university based in London, England, UK, with additional international campuses (e.g., Dubai, Mauritius). It offers a wide range of undergraduate and postgraduate programs in arts, business, science, law, health, media, and technology, focusing on career-relevant education, practical learning, and global opportunities. The university serves a diverse student body from around the world and emphasizes industry links and student experience.', 'https://www.mdx.ac.uk', '#501 :Times Higher Education (THE) World University Rankings 2026', '1992', '15855'),
(148, 'Middlesex University Dubai', 'united arab emirates', '0', '/catalog/University_Favicon/dubai/Middlesex University Dubai_Favicon.png', 'Dubai, United Arab Emirates', 'Middlesex University Dubai is the overseas campus of Middlesex University London offering UK degrees in business and computing.', 'https://www.mdx.ac.ae', '651?700 (QS)', '2005', '4500'),
(149, 'Minnesota State University - Mankato', 'United States', '0', '/catalog/University_logo//1723020375-Minnesota%20State%20University%20-%20Mankato_Favicon.png', 'Mankato, Minnesota', 'Minnesota State University, Mankato is a public university in Mankato, Minnesota, USA, known for combining ?big ideas with real-world thinking? across a wide range of academic programs. Founded in 1868, it offers over 130 undergraduate and 80+ graduate programs and serves a diverse student body. The campus fosters hands-on learning, research opportunities, and community engagement. It is the second-largest university in Minnesota and part of the Minnesota State system.', 'https://www.mnsu.edu', '#1667 globally in the 2025 EduRank', '1868', '15,721'),
(150, 'Mississippi State University', 'United States', '0', '/catalog/University_Favicon/usa/Mississippi State University_Favicon.png', 'Starkville, Mississippi', 'Mississippi State University (MSU) is a public land-grant research university with a strong focus on education, research, and community service. It is classified as an R1: Doctoral University ? Very High Research Activity and participates in land-grant, sea-grant, and space-grant programs. MSU offers more than 180 baccalaureate, graduate, and professional degree programs across multiple colleges including engineering, agriculture, business, education, and veterinary medicine ? the latter being the only accredited program in Mississippi.', 'https://www.msstate.edu', '#1200 in the world by QS World University Rankings', '1878', '23,150'),
(151, 'Missouri University of Science and Technology', 'United States', '0', '/catalog/University_logo//1723211108-Missouri%20University%20of%20Science%20and%20Technology_Favicon.png', 'Rolla, Missouri', 'Missouri University of Science and Technology (commonly Missouri S&T) is a public research university focused on science, engineering, and technology education. It offers a wide range of undergraduate and graduate programs with strong emphasis on research, innovation, and hands-on learning in STEM fields.', 'https://www.mst.edu', '#694 in the world by EduRank', '1870', '6,456'),
(152, 'Montana State University, Billings', 'United States', '0', '/catalog/University_logo//1723263890-Montana%20State%20University-%20Billings_Favicon.png', 'Billings, Montana', 'Montana State University Billings is a public university located in Billings, Montana, USA, offering undergraduate and graduate programs across business, education, health sciences, liberal arts, and technology. Established in 1927, it focuses on accessible, career-oriented education with small class sizes and strong student support. The university serves as a key educational hub for south-central Montana, emphasizing community engagement and practical learning.', 'https://www.msubillings.edu', '#3805 globally (EduRank 2025)', '1927', '4,129'),
(153, 'Montclair State University', 'United States', '0', '/catalog/University_logo//1723020818-Montclair%20State%20University_Favicon.png', 'Montclair, New Jersey, USA', 'Montclair State University is a large public research university offering comprehensive academic programs. It is known for education, business, arts, sciences, and communication studies. The university emphasizes research, innovation, and community engagement with strong student support services.', 'https://www.montclair.edu', '#1201?1500 in the world by THE World University Rankings', '1908', '21000'),
(154, 'Mount Allison University', 'Canada', '/catalog/University_Banner/canada-banner/MountAllisonUniversitybanner.png', '/catalog/University_Favicon/canada/Mount Allison University Favicon.png', 'Sackville, New Brunswick, Canada', 'Mount Allison University is a highly regarded public undergraduate university known for arts and science education.', 'https://www.mta.ca', 'Not ranked globally', '1839', '2300'),
(155, 'Mount Saint Vincent University', 'Canada', '/catalog/University_Banner/canada-banner/MountSaintUniversitybanner.png', '/catalog/University_Favicon/canada/Mount Saint University  Favicon.png', 'Halifax, Nova Scotia, Canada', 'Mount Saint Vincent University is a public undergraduate university known for liberal arts and professional studies.', 'https://www.msvu.ca', 'Not ranked globally', '1873', '4000'),
(156, 'Mount St. Mary\'s University', 'United States', '0', '0', 'Emmitsburg, Maryland', 'Mount St. Mary?s University is a private Catholic liberal arts university with strong undergraduate and graduate offerings. It features more than 80 majors, minors, and special programs, and is known for its emphasis on personalized education, liberal arts, business, natural sciences, and professional development. It also hosts the largest Catholic seminary in the United States.', 'https://www.msmary.edu', '#4024 in the world by EduRank', '1808', '2,411'),
(157, 'Munster Technological University (CIT)', 'Ireland', '/catalog/University_Banner/Ireland/CorkInstituteofTechnologybanner.png', '/catalog/University_Favicon/ireland/Munster Technological University_Favicon.png', 'Cork', 'Munster Technological University (MTU) is a public technological university in Ireland, formed on 1 January 2021 through the merger of Cork Institute of Technology (CIT) and the Institute of Technology, Tralee. It has six campuses across Cork and County Kerry and focuses on industry-connected education, applied research, and practical skills development. MTU offers undergraduate, postgraduate, and research programs across a wide range of disciplines with strong regional and international engagement. It serves a diverse student body and works closely with industry and community partners.', 'https://www.mtu.ie', '#1974 globally according to the UniRank World University Rankings', '2021', '18,000'),
(158, 'Murray State University', 'United States', '0', '/catalog/University_Favicon/usa/Murray State University_Favicon.png', 'Murray, Kentucky', 'Murray State University (MSU) is a public research university and part of the Kentucky public university system. Founded as a teachers? college, it has grown into a comprehensive university offering undergraduate, graduate, and professional programs across disciplines such as business, engineering, education, health sciences, liberal arts, and sciences. MSU is known for strong community engagement, personalized learning environments, and nationally recognized value and quality of education.', 'https://www.murraystate.edu', '#1927 in the world by EduRank', '1922', '9,932'),
(159, 'National College of Ireland', 'Ireland', '/catalog/University_Banner/Ireland/NationalCollegeofIrelandbanner.png', '/catalog/University_Favicon/ireland/National College of Ireland_Favicon.png', 'Dublin, Ireland', 'National College of Ireland is a specialist institution focused on business, computing, finance, and psychology. It is known for strong industry links and professional programs aligned with employer needs. The college emphasizes practical skills, career readiness, and flexible learning options. It has strong connections with Ireland?s technology and finance sectors.', 'https://www.ncirl.ie', 'Not ranked globally', '1951', '6000'),
(160, 'Navitas', 'united kingdom', '/catalog/University_Banner/Navitasbanner.png', '/catalog/University_Favicon/NavitasFavicon.png', 'Global', 'Navitas is a global education provider offering pathway and transnational education programs with universities worldwide.', 'https://www.navitas.com', 'Not applicable', '1994', ''),
(161, 'Nelson Marlborough Institute of Technology (NMIT)', 'new Zealand', '/catalog/University_Banner/NewZealand/NelsonMarlboroughInstituteofTechnology (NMIT)banner.png', '/catalog/University_Favicon/nz/Nelson Marlborough Institute of Technology_Favicon.png', 'Nelson', 'Nelson Marlborough Institute of Technology (NMIT) is a public tertiary education institute in Nelson, New Zealand, offering vocational, undergraduate, and selected postgraduate programmes with a strong focus on hands-on learning and industry-relevant skills. Established in 1905, NMIT provides over 100 qualifications and is widely recognised for its applied training in areas like aquaculture, maritime, viticulture, business and engineering. It has campuses across Nelson, Blenheim (Marlborough), Richmond and Woodbourne and fosters close ties with local industries. NMIT emphasises practical experience, personalised support, and work-ready graduates.', 'https://www.nmit.ac.nz', '#8808 globally according to UniRank?s world university ranking', '1905', '7,000'),
(162, 'New England College', 'United States', '0', '/catalog/University_Favicon/usa/New England College_Favicon_Favicon.png', 'Henniker, New Hampshire, USA', 'New England College is a private liberal arts institution focused on professional and graduate studies.', 'https://www.nec.edu', 'Not ranked globally', '1946', '2800'),
(163, 'New Jersey Institute of Technology', 'United States', '0', '/catalog/University_Favicon/usa/New Jersey Institute of Technology_Favicon.png', 'Newark, New Jersey, USA', 'New Jersey Institute of Technology is a public research university specializing in engineering, science, technology, and computing. It is known for innovation, research output, and strong industry partnerships. The university emphasizes STEM education, entrepreneurship, and applied research.', 'https://www.njit.edu', '#651?700 in the world by QS World University Rankings', '1881', '11000'),
(164, 'New Zealand Enquiry', 'new Zealand', '0', '/catalog/University_Favicon/ireland/Enquiry_Favicon.png', 'New Zealand', 'New Zealand Enquiry is an education advisory service supporting students applying to New Zealand institutions.', 'Not applicable', 'Not applicable', 'Not applicable', ''),
(165, 'New Zealand Skills and Education Group', 'new Zealand', '0', '0', 'Auckland, New Zealand', 'New Zealand Skills and Education Group (NZSEG) is a private education provider offering vocational and higher education programs.', 'https://www.nzseg.com', 'Not ranked globally', '2003', '5000'),
(166, 'Newcastle University', 'united kingdom', '/catalog/University_Banner/Newcastle University Banner.png', '/catalog/University_Favicon/Newcastle UniversityFavicon.png', 'Newcastle upon Tyne, England, UK', 'Newcastle University is a prestigious public research university and a member of the Russell Group. It is internationally recognized for research excellence in medicine, engineering, sciences, and social sciences. The university offers strong global partnerships and a vibrant campus experience.', 'https://www.ncl.ac.uk', '#110 in the world by QS World University Rankings', '1834', '29000'),
(167, 'Niagara College of Applied Arts and Technology', 'Canada', '/catalog/University_Banner/canada-banner/NiagaraCollegeofAppliedArtsandTechnologybanner.png', '/catalog/University_Favicon/canada/Niagara College of Applied Arts and Technology Favicon.png', 'Welland, Ontario, Canada', 'Niagara College of Applied Arts and Technology is a public college known for applied learning and industry-driven programs. It offers diplomas, degrees, and graduate certificates in business, hospitality, technology, health, and environmental studies. The college emphasizes experiential education, co-op programs, and strong employer partnerships.', 'https://www.niagaracollege.ca', 'Not ranked (college, not university)', '1967', '12000'),
(168, 'Niagara University - Canada', 'Canada', '0', '/catalog/University_Favicon/canada/Niagara University_Favicon.png', 'Vaughan, Ontario, Canada', 'Niagara University ? Canada Campus offers undergraduate and postgraduate programs in business and education.', 'https://niagaracollegetoronto.ca', 'Not ranked globally', '2019', '1500'),
(169, 'Niagara University - USA', 'United States', '0', '0', 'Lewiston, New York', 'Niagara University is a private Catholic university founded in the Vincentian tradition, offering undergraduate, graduate, and doctoral programs across arts and sciences, business, education, nursing, and hospitality & tourism management, with a strong focus on community service and academic excellence.', 'https://www.niagara.edu', '#2962 in the world by EduRank', '1856', '4,221'),
(170, 'Nipissing University', 'Canada', '/catalog/University_Banner/canada-banner/NipissingUniversitybanner.png', '/catalog/University_Favicon/canada/Nipissing University Favicon.png', 'North Bay, Ontario, Canada', 'Nipissing University is a public undergraduate-focused university with strengths in education and arts.', 'https://www.nipissingu.ca', 'Not ranked globally', '1992', '6000'),
(171, 'Northeastern Illinois University', 'United States', '0', '/catalog/University_Favicon/usa/Northeastern Illinois University_Favicon.png', 'Chicago, Illinois', 'Northeastern Illinois University (NEIU) is a public university known for its diverse student body, strong emphasis on affordability and access, and commitment to student success. It offers a wide range of undergraduate and graduate programs across arts, sciences, education, business, and more, with small class sizes and a focus on inclusive learning.', 'https://www.neiu.edu', '#2328 in the world (EduRank)', '1867', '5,778'),
(172, 'Northern Lights College', 'Canada', '/catalog/University_Banner/canada-banner/NorthernLightsCollegebanner.png', '/catalog/University_Favicon/canada/Northern Lights College Favicon.png', 'Dawson Creek, British Columbia, Canada', 'Northern Lights College is a public community college serving northern British Columbia. It offers certificates, diplomas, trades, and applied programs aligned with regional workforce needs. The college emphasizes hands-on training, flexible learning, and strong community and industry partnerships.', 'https://www.nlc.bc.ca', 'Not ranked (college, not university)', '1975', '3500'),
(173, 'Northumbria University London Campus', 'united kingdom', '/catalog/University_Banner/Northumbria University London Campus banner--banner.png', '/catalog/University_Favicon/Northumbria University London CampusFavicon.png', 'London, England, UK', 'Northumbria University London is the London campus of Northumbria University, offering career-focused undergraduate and postgraduate programs. It specializes in business, finance, project management, and technology-related fields. The campus emphasizes employability, professional accreditation, and industry-aligned education.', 'https://www.northumbria.ac.uk/london', 'Parent university #501?550 by QS', '2014', '5000'),
(174, 'Northumbria University Newcastle Campus', 'united kingdom', '/catalog/University_Banner/Northumbria University Newcastle Campus  Banner.png', '/catalog/University_Favicon/Northumbria University Newcastle CampusFavicon.png', 'Newcastle upon Tyne, England, UK', 'Northumbria University is a public research university known for strong links with industry and professional accreditation. It offers a broad range of programs in business, engineering, law, design, and health sciences. The university focuses on employability, applied research, and innovation with a global outlook.', 'https://www.northumbria.ac.uk', '#501?550 in the world by QS World University Rankings', '1969', '38000'),
(175, 'Northwest Missouri State University', 'United States', '0', '/catalog/University_Favicon/usa/Northwest Missouri State University_Favicon.png', 'Maryville, Missouri, USA', 'Northwest Missouri State University is a public university recognized for teaching quality and affordability.', 'https://www.nwmissouri.edu', 'Not ranked globally', '1905', '8500'),
(176, 'Northwood University', 'United States', '0', '/catalog/University_Favicon/usa/Northwood University_Favicon.png', 'Midland, Michigan, USA', 'Northwood University is a private university known for business, management, and automotive-focused programs. It emphasizes entrepreneurial thinking and practical experience with a strong network in industry sectors. Northwood combines classroom learning with applied projects, leadership development, and career preparation.', 'https://www.northwood.edu', 'Not in major global rankings', '1959', '3500'),
(177, 'Nottingham Trent University', 'united kingdom', '/catalog/University_Banner/Nottingham Trent University  Banner.png', '/catalog/University_Favicon/Nottingham Trent UniversityFavicon.png', 'Nottingham, England, UK', 'Nottingham Trent University is a large public university known for teaching quality and employability. It offers a wide range of programs across business, arts, design, law, engineering, and sciences. The university emphasizes practical learning, industry collaboration, and modern campus facilities.', 'https://www.ntu.ac.uk', '#595 in the world by QS World University Rankings', '1843', '38000');
INSERT INTO `university` (`id`, `name`, `country`, `banner_image`, `logo_image`, `city`, `description`, `link`, `ranking`, `established_year`, `enroll_students`) VALUES
(178, 'Nova Southeastern University', 'United States', '0', '0', 'Fort Lauderdale?Davie, Florida', 'Nova Southeastern University is a private research university offering a wide range of undergraduate, graduate, and professional degree programs. It is especially known for health sciences, psychology, education, business, and law. The university combines research, innovation, and real-world training with modern facilities and a diverse student population.', 'https://www.nova.edu', '#1001?1200 in the world by THE World University Rankings', '1964', '20,877'),
(179, 'Ohio Wesleyan University', 'United States', '0', '0', 'Delaware, Ohio', 'Ohio Wesleyan University (OWU) is a private liberal arts university affiliated historically with the United Methodist Church. Founded in the 19th century, it offers a broad liberal arts curriculum with more than 70 undergraduate majors including sciences, humanities, business, and social sciences, and is known for personalized teaching, study abroad programs, research opportunities, and strong alumni outcomes. OWU is a member of the Five Colleges of Ohio and competes in NCAA Division III athletics.', 'https://www.owu.edu', '#1850 in the world by CWUR', '1842', '1,650'),
(180, 'Oklahoma City University', 'United States', '0', '/catalog/University_Favicon/usa/Oklahoma City University_Favicon.png', 'Oklahoma City, Oklahoma', 'Oklahoma City University (OCU) is a private, nonprofit university established by the United Methodist Church and located on a scenic 104-acre campus in the heart of Oklahoma City. It offers more than 70 undergraduate majors and 20 graduate programs, including arts & sciences, business, nursing, law, performing arts, and health professions. OCU emphasizes personalized attention with small class sizes (student-to-faculty ratio ~11:1), global opportunities, leadership development, and a strong tradition in the performing arts and professional education.', 'https://www.okcu.edu', '#2203 in the world by EduRank', '1904', '2,900'),
(181, 'Ontario Tech University', 'Canada', '0', '0', 'Oshawa, Ontario, Canada', 'Ontario Tech University is a public university focused on technology, engineering, and innovation.', 'https://ontariotechu.ca', 'Top 1000 (QS)', '2002', '11000'),
(182, 'Oregon State University', 'United States', '0', '/catalog/University_logo//1723263992-Oregon%20State%20University_Favicon.png', 'Corvallis, Oregon', 'Oregon State University (OSU) is a public land-grant research university known for its strong academic programs in science, engineering, agriculture, forestry, marine sciences, environmental research, and more. It is classified as an R1: Doctoral University with very high research activity and is one of only a few institutions in the U.S. holding land, sea, space, and sun grant designations. OSU offers more than 200 undergraduate, graduate, and doctoral degree programs across its colleges and campuses.', 'https://www.oregonstate.edu', '#291 in the world by CWUR', '1868', '38,460'),
(183, 'Oxford Brookes University', 'united kingdom', '0', '/catalog/University_Favicon/Oxford Brookes University_Favicon.png', 'Oxford, England, UK', 'Oxford Brookes University is a public university known for teaching excellence and applied research. It offers a wide range of programs in business, architecture, engineering, health, and social sciences. The university emphasizes employability, sustainability, and strong industry partnerships.', 'https://www.brookes.ac.uk', '#413 in the world by QS World University Rankings', '1865', '18000'),
(184, 'Oxford International Education Group', 'united kingdom', '/catalog/University_Banner/Oxford International Education Group   Banner.png', '/catalog/University_Favicon/Oxford International Education Group Favicon.png', 'United Kingdom', 'Oxford International Education Group delivers pathway programs, English language training, and higher education services.', 'https://www.oxfordinternationaleducationgroup.com', 'Not applicable', '1991', ''),
(185, 'Pacific International Hotel Management School (PIHMS)', 'new Zealand', '/catalog/University_Banner/NewZealand/PacificInternationalHotelManagementSchool(PIHMS)banner.png', '/catalog/University_Favicon/nz/Pacific International Hotel Management School_Favicon.png', 'New Plymouth, New Zealand', 'Pacific International Hotel Management School (PIHMS) specializes in hotel and hospitality management education.', 'https://www.pihms.ac.nz', 'Not ranked globally', '1995', '400'),
(186, 'Palm Beach Atlantic University', 'United States', '0', '0', 'West Palm Beach, Florida, USA', 'Palm Beach Atlantic University is a private Christian university offering undergraduate and graduate programs. It emphasizes small class sizes, faith-based education, and personal development. The university is known for programs in business, nursing, education, and the arts.', 'https://www.pba.edu', 'Not ranked in major global rankings', '1968', '3900'),
(187, 'Pepperdine University', 'United States', '0', '0', 'Malibu, California, USA', 'Pepperdine University is a private Christian research university known for business, law, and international studies.', 'https://www.pepperdine.edu', 'Top 1000 (QS)', '1937', '10000'),
(188, 'Plymouth University', 'united kingdom', '/catalog/University_Banner/Plymouth University Banner.png', '/catalog/University_Favicon/Plymouth University  Favicon2.png', 'Plymouth, England', 'The University of Plymouth is a public research university located in Plymouth, England, UK, known for its strong emphasis on research, particularly in marine science, environmental studies, and sustainability. It combines practical, research-led teaching with industry links and community engagement, helping graduates succeed globally. The institution has modern facilities and a diverse international student body. It traces its origins back to 1862 as the School of Navigation and gained full university status in 1992.', 'https://www.plymouth.ac.uk', '#613 globally in the QS World University Rankings', '1992', '18,910'),
(189, 'Post University', 'United States', '0', '0', 'Waterbury, Connecticut, USA', 'Post University is a private university offering flexible undergraduate and graduate programs, especially in business and online education.', 'https://post.edu', 'Not ranked globally', '1890', '9000'),
(190, 'PSB Academy', 'singapore', '0', '/catalog/University_Favicon/singapore/psb_academy_Favicon.png', 'Singapore', 'PSB Academy is a private education institution offering pathway and degree programs with global universities.', 'https://www.psb-academy.edu.sg', 'Not ranked globally', '1964', '12000'),
(191, 'Purdue University Northwest', 'United States', '0', '0', 'Hammond & Westville, Indiana, USA', 'Purdue University Northwest is a public university offering undergraduate and graduate programs with a focus on applied research. It is known for engineering, technology, business, and health sciences. The university emphasizes hands-on learning, industry collaboration, and regional economic development.', 'https://www.pnw.edu', 'Not ranked in major global rankings', '2016', '8000'),
(192, 'QA Higher Education', 'united kingdom', '0', '/catalog/University_Favicon/QA Higher Education_Favicon.png', 'United Kingdom', 'QA Higher Education provides pathway, degree, and professional education in partnership with UK universities.', 'https://www.qahe.com', 'Not applicable', '2001', ''),
(193, 'Queen Mary University London', 'united kingdom', '/catalog/University_Banner/Queen Mary University_London Banner.png', '/catalog/University_Favicon/QueenMaryUniversityLondonFavicon.png', 'London, England', 'Queen Mary University of London (QMUL) is a public research university and a member of the Russell Group of research-intensive institutions, known for strong teaching and research across humanities, sciences, engineering, law, medicine and more, with a diverse international community.', 'https://www.qmul.ac.uk', '#110 in the QS World University Rankings', '1785', '32,000'),
(194, 'Queens University Belfast', 'united kingdom', '/catalog/University_Banner/Queens University Belfast    Banner.png', '/catalog/University_Favicon/QueensUniversityBelfastFavicon.png', 'Belfast, Northern Ireland', 'Queen?s University Belfast is a public research university and the only Russell Group member in Northern Ireland, known for strong research, global engagement, and a wide range of undergraduate and postgraduate programs across sciences, arts, engineering, medicine, and more.', 'https://www.qub.ac.uk', '#199 in the QS World University Rankings', '1845', '21,045'),
(195, 'Randolph College', 'United States', '0', '0', 'Lynchburg, Virginia, USA', 'Randolph College is a private liberal arts college focused on undergraduate education. It emphasizes individualized learning, leadership development, and experiential opportunities. The college offers programs in arts, sciences, and professional studies with a strong emphasis on critical thinking.', 'https://www.randolphcollege.edu', 'Not ranked in major global rankings', '1891', '600'),
(196, 'Ravensbourne University London', 'united kingdom', '0', '/catalog/University_Favicon/Ravensbourne University_Favicon.png', 'London, England, UK', 'Ravensbourne University London is a specialist university focused on digital media, design, fashion, and broadcasting. It offers industry-focused programs with strong professional engagement. The university emphasizes creativity, innovation, and real-world projects. It has close links with London?s creative and digital industries.', 'https://www.ravensbourne.ac.uk', 'Not ranked globally', '1962', '4000'),
(197, 'Regent College London', 'United Kingdom', '0', '0', 'London, England, UK', 'Regent College London is a private higher education provider offering business, computing, and health programs.', 'https://www.rcl.ac.uk', 'Not ranked globally', '2010', '6000'),
(198, 'Regents University', 'united kingdom', '/catalog/University_Banner/Regents University  Banner.png', '/catalog/University_Favicon/RegentsUniversityFavicon.png', 'London, England, UK', 'Regent?s University London is a private university offering internationally focused undergraduate and postgraduate programs. It is known for business, fashion, psychology, film, and international relations. The university emphasizes small class sizes, global outlook, and strong industry connections.', 'https://www.regents.ac.uk', 'Not ranked in major global rankings', '1984', '4500'),
(199, 'Rivier University', 'United States', '0', '/catalog/University_logo//1723119208-Rivier%20University_Favicon.png', 'Nashua, New Hampshire, USA', 'Rivier University is a private Catholic university offering programs in nursing, business, and education.', 'https://www.rivier.edu', 'Not ranked globally', '1933', '2400'),
(200, 'Robert Gordon University', 'united kingdom', '0', '/catalog/University_Favicon/Robert Gordon University_Favicon.png', 'Aberdeen, Scotland, UK', 'Robert Gordon University is a modern public university with strengths in professional education and applied research. It is especially known for business, engineering, health, and computing programs. The university maintains close ties with industry and offers practical learning, internships, and career support.', 'https://www.rgu.ac.uk', '#801?1000 in the world by QS World University Rankings', '1992', '16,000'),
(201, 'Robert Morris University', 'United States', '0', '0', 'Chicago, Illinois', 'Robert Morris University (RMU) is a private university located in Moon Township (near Pittsburgh), Pennsylvania, USA. Founded in 1921, it offers undergraduate, graduate, and professional programs across business, engineering, sciences, nursing, communications, and more. RMU emphasizes career-ready education with internships and experiential learning, and many students progress quickly into fields such as technology, business, and healthcare after graduation.', 'https://www.rmu.edu/', '#2813 in the world by EduRank', '1913', '2307'),
(202, 'Rochester Institute of Technology', 'United States', '0', '/catalog/University_Favicon/usa/Rochester Institute of Technology_Favicon.png', 'Henrietta, New York', 'Rochester Institute of Technology (RIT) is a private research university in Henrietta (near Rochester), New York, USA, known for its strong emphasis on career-focused education, cooperative work experiences (co-ops), and blend of technology, arts, and design. Founded in 1829, it offers a wide range of undergraduate, graduate, and professional programs with global campuses and diverse student representation. RIT?s educational model highlights experiential learning and industry engagement.', 'https://www.rit.edu', '#740 globally according to the Times Higher Education World University Rankings', '1829', '20,570'),
(203, 'Roger Williams University', 'United States', '0', '0', 'Bristol, Rhode Island', 'Roger Williams University (RWU) is a private liberal arts university known for its experiential learning, personalized teaching, diverse academic offerings, and strong professional outcomes. Founded in 1956, RWU offers more than 50 undergraduate majors and professional programs spanning business, architecture, engineering, law, justice studies, marine science, and liberal arts. Its coastal location supports distinctive programs like marine biology and maritime studies, and the campus fosters hands-on opportunities and career preparation.', 'https://www.rwu.edu', '#2633 in the world by EduRank', '1956', '4,021'),
(204, 'Rose-Hulman Institute of Technology', 'United States', '0', '0', 'Terre Haute, Indiana, USA', 'Rose-Hulman Institute of Technology is a private STEM-focused institution known for engineering, math, and science education.', 'https://www.rose-hulman.edu', 'Not ranked globally', '1874', '2200'),
(205, 'Royal Holloway University of London', 'united kingdom', '/catalog/University_Banner/Royal Holloway University of London  Banner.png', '/catalog/University_Favicon/RoyalHollowayUniversityofLondonFavicon.png', 'Egham, England, UK', 'Royal Holloway, University of London is a public research university and a member of the University of London. It is known for strengths in humanities, social sciences, sciences, and business. The university combines research excellence with a strong campus-based student experience.', 'https://www.royalholloway.ac.uk', '#402 in the world by QS World University Rankings', '1879', '12000'),
(206, 'Royal Roads University', 'Canada', '/catalog/University_Banner/canada-banner/RoyalRoadsUniversitybanner.png', '/catalog/University_Favicon/canada/Royal Roads University Favicon.png', 'Victoria, British Columbia, Canada', 'Royal Roads University is a public university focused on applied research, leadership, and professional programs.', 'https://www.royalroads.ca', 'Not ranked globally', '1995', '5500'),
(207, 'Rutgers University', 'United States', '0', '0', 'New Brunswick, New Jersey', 'New Brunswick, New Jersey', 'https://www.rutgers.edu', '#801 in the world by QS World University Rankings', '1766', '71,000'),
(208, 'Saint Louis University', 'United States', '0', '/catalog/University_Favicon/usa/Saint Louis University_Favicon.png', 'St. Louis, Missouri, USA', 'Saint Louis University is a private Jesuit research university known for strong academics and ethical education. It offers a wide range of undergraduate, graduate, and professional programs, especially in health sciences, business, engineering, and law. The university emphasizes research, service learning, and global engagement.', 'https://www.slu.edu', '#451?500 in the world by QS World University Rankings', '1818', '13000'),
(209, 'Saint Peters University', 'United States', '0', '/catalog/University_Favicon/usa/Saint Peter\'s University_Favicon.png', 'Jersey City, New Jersey', 'Saint Peter?s University is a private Jesuit Catholic university founded in 1872, known for its liberal arts education, strong focus on whole-person formation, experiential learning, community engagement, and Division I athletics in the Metro Atlantic Athletic Conference.', 'https://www.saintpeters.edu', '#3600 in the world by EduRank', '1872', '3,572'),
(210, 'Salve Regina University', 'United States', '0', '0', 'Newport, Rhode Island', 'Salve Regina University is a private Catholic university founded and guided by the Sisters of Mercy. It offers more than 100 undergraduate majors and graduate programs across liberal arts, sciences, business, health professions, and more, emphasizing engaged learning, professional preparation, and strong outcomes. Its picturesque 80-acre campus includes historic Gilded Age estates along the Atlantic Coast and houses centers like the Pell Center for International Relations and Public Policy.', 'https://salve.edu', '#3804 in the world by EduRank', '1934', '2,785'),
(211, 'San Jose State University', 'United States', '0', '/catalog/University_Favicon/usa/San Jose State University_Favicon.png', 'San Jos?, California', 'San Jos? State University (SJSU) is a public research university and the founding campus of the California State University system. Established as the first normal school in California, it has grown into a large urban university offering over 250 undergraduate and graduate programs across nine colleges. SJSU is known for its strong industry connections ? especially in engineering, computer science, business, and technology ? and its strategic location in the heart of Silicon Valley. It is classified as an R2: High Research Activity institution and serves a highly diverse student body.', 'https://www.sjsu.edu', '#1513 in the world by CWUR', '1857', '37,661'),
(212, 'San Mateo College', 'United States', '0', '0', 'San Mateo, California', 'The College of San Mateo is a public community college located in San Mateo, California, USA, serving as a gateway to higher education with associate degrees, certificates, and transfer pathways to four-year universities. Founded in 1922, it offers a wide range of academic programs and support services, including leadership, athletics, tutoring, and career development. The campus sits on a scenic hilltop with views of the San Francisco Bay and serves a diverse student population.', 'https://www.collegeofsanmateo.edu', '#8471 globally in the Webometrics World University Ranking', '1922', '12,900'),
(213, 'Saskatchewan Polytechnic', 'Canada', '/catalog/University_Banner/canada-banner/SaintMarysUniversitybanner.png', '/catalog/University_Favicon/canada/saskpolytech - favicon.png', 'Multiple cities, Saskatchewan, Canada', 'Saskatchewan Polytechnic is a public polytechnic institution offering applied degrees, diplomas, and certificates. It focuses on hands-on training in technology, health, trades, business, and agriculture. The institution emphasizes workforce readiness, industry partnerships, and practical skills development.', 'https://saskpolytech.ca', 'Not ranked (polytechnic)', '1981', '15000'),
(214, 'Schiller University', '', '0', '0', 'Tampa, Florida, USA', 'Schiller University is a private international university offering American degree programs across global campuses.', 'https://www.schiller.edu', 'Not ranked globally', '1964', '3000'),
(215, 'Schreiner University', 'United States', '0', '0', 'Kerrville, Texas', 'Schreiner University is a private Presbyterian university known for its personalized education and close-knit campus community. It offers undergraduate programs in arts, sciences, health, business, education, and graduate degree options like MBA and Master of Education. The university emphasizes individualized mentoring and holistic student support.', 'https://schreiner.edu', '#5734 globally (EduRank)', '1923', '1,208'),
(216, 'Seattle University', 'United States', '0', '/catalog/University_Favicon/usa/Seattle University_Favicon.png', 'Seattle, Washington', 'Seattle University is a private Jesuit Catholic university known for its strong emphasis on holistic education, professional formation, community engagement, and academic excellence across arts, sciences, business, engineering, law, and health disciplines.', 'https://seattleu.edu', '#1201 in the QS World University Rankings', '1891', '7,189'),
(217, 'Selkirk College', 'Canada', '/catalog/University_Banner/canada-banner/SelkirkCollegebanner.png', '/catalog/University_Favicon/canada/Selkirk College  Favicon.png', 'Castlegar, British Columbia, Canada', 'Selkirk College is a public college offering certificates, diplomas, and university transfer programs. It focuses on applied learning, trades, health, business, and arts education. The college emphasizes small class sizes, community engagement, and practical workforce-oriented training.', 'https://selkirk.ca', 'Not ranked (college, not university)', '1966', '2300'),
(218, 'Seneca College', 'Canada', '/catalog/University_Banner/canada-banner/SenecaCollegebanner.png', '/catalog/University_Favicon/canada/Seneca College Favicon.png', 'North York, Ontario', 'Seneca College (officially Seneca Polytechnic) is a public college of applied arts and technology based in Toronto and the Greater Toronto Area, Ontario, Canada. It offers a wide range of certificate, diploma, advanced diploma, degree and graduate certificate programs with a strong emphasis on career-focused, hands-on learning and industry partnerships across fields such as business, technology, health, creative arts, aviation, and community services. The college serves a large multicultural student community and provides pathways to further education and employment.', 'https://www.senecacollege.ca', '#4381 globally (Webometrics)', '1967', '97500'),
(219, 'Shannon College of Hotel Management', 'Ireland', '/catalog/University_Banner/Ireland/ShannonCollegeofHotelManagementbanner.png', '/catalog/University_Favicon/ireland/Shannon College of Hotel Management_Favicon.png', 'Shannon, County Clare, Ireland', 'Shannon College of Hotel Management is a specialist hospitality management college linked to NUI Galway.', 'https://www.shannoncollege.com', 'Not ranked globally', '1951', '450'),
(220, 'Sheffield Hallam University', 'united kingdom', '/catalog/University_Banner/Sheffield-Hallam-University-banner.png', '/catalog/University_Favicon/Sheffield Hallam UniversityFavicon.png', 'Sheffield, England, UK', 'Sheffield Hallam University is one of the UK?s largest public universities with a strong focus on employability. It offers undergraduate and postgraduate programs across business, engineering, health, and creative disciplines. The university is known for applied research and strong employer partnerships. It emphasizes real-world learning and professional readiness.', 'https://www.shu.ac.uk', '1001?1200 (THE)', '1969', '30000'),
(221, 'Shenandoah University', 'United States', '0', '0', 'Winchester, Virginia, USA', 'Shenandoah University is a private university known for performing arts, health professions, and liberal arts.', 'https://www.su.edu', 'Not ranked globally', '1875', '4000'),
(222, 'Sheridan College', 'Canada', '/catalog/University_Banner/canada-banner/SheridanCollegebanner.png', '/catalog/University_Favicon/canada/Sheridan College  Favicon.png', 'Oakville, Ontario, Canada', 'Sheridan College is a leading public college known for creativity, animation, design, and applied technology programs. It offers diplomas, degrees, and postgraduate certificates with strong industry alignment. Sheridan emphasizes hands-on learning, innovation, and career readiness across diverse fields.', 'https://www.sheridancollege.ca', 'Not ranked (college, not university)', '1967', '23000'),
(223, 'SOAS University of London', 'united kingdom', '0', '/catalog/University_Favicon/SOAS University of London_Favicon.png', 'London, England, UK', 'SOAS University of London specializes in the study of Asia, Africa, and the Middle East with a strong humanities focus.', 'https://www.soas.ac.uk', '511?520 (QS)', '1916', '6000'),
(224, 'Solent University', 'united kingdom', '/catalog/University_Banner/Solent University  Banner.png', '/catalog/University_Favicon/Solent UniversityFavicon.png', 'Southampton, England, UK', 'Solent University is a modern public university known for practice-based education. It offers programs in maritime studies, business, media, sport, engineering, and creative industries. The university emphasizes industry engagement, applied learning, and employability. It maintains strong regional and professional links.', 'https://www.solent.ac.uk', '1201?1500 (THE)', '1856', '11000'),
(225, 'South East Technological University (IT Carlow)', 'Ireland', '/catalog/University_Banner/Ireland/InstituteofTechnologyCarlowbanner.png', '/catalog/University_Favicon/ireland/South East Technological University_Favicon.png', 'Carlow, Ireland', 'South East Technological University (SETU Carlow) is a public technological university formed through institutional merger.', 'https://www.setu.ie', 'Not ranked globally', '1970', '9000'),
(226, 'South East Technological University (WIT)', 'Ireland', '/catalog/University_Banner/Ireland/WaterfordInstituteofTechnologybanner.png', '/catalog/University_Favicon/ireland/South East Technological University_Favicon.png', 'Waterford, Ireland', 'South East Technological University, formerly WIT, is a public technological university serving Ireland?s southeast region. It offers programs in engineering, science, business, computing, health, and creative disciplines. The university focuses on applied research, innovation, and industry engagement. It supports regional development and workforce readiness.', 'https://www.setu.ie', 'Not ranked globally', '2022', '18000'),
(227, 'Southeast Missouri State University', 'United States', '0', '/catalog/University_Favicon/usa/Southeast Missouri State University_Favicon.png', 'Cape Girardeau, Missouri, USA', 'Southeast Missouri State University is a public university offering comprehensive undergraduate and graduate programs. It is known for education, business, health sciences, and arts programs with a strong regional focus. The university emphasizes practical learning, internships, and student success initiatives.', 'https://semo.edu', 'Not ranked in major global rankings', '1873', '10000'),
(228, 'Southern Cross University', 'Australia', '/catalog/University_Banner/Australia/SouthernCrossUniversity-Melbourne,SydneyandPerthCampusbanner.png', '/catalog/University_Favicon/australia/Southern Cross University_Favicon.png', 'Lismore & Gold Coast, Australia', 'Southern Cross University is a public university focused on health, environment, and applied research.', 'https://www.scu.edu.au', '601?650 (QS)', '1994', '15000'),
(229, 'Southern Illinois University', 'United States', '0', '0', 'Carbondale, Illinois', 'Southern Illinois University Carbondale (SIUC) is a public, research-focused university and the flagship campus of the Southern Illinois University system. It was originally founded as a teachers? college and expanded into a comprehensive research-intensive institution offering undergraduate, graduate, and professional degrees. The university is classified among ?R1: Doctoral Universities ? very high research activity.?', 'https://www.siu.edu', '#957 in the world by CWUR', '1869', '11,359'),
(230, 'Southern Institute of Technology', 'new Zealand', '/catalog/University_Banner/NewZealand/SouthernInstituteofTechnologybanner.png', '/catalog/University_Favicon/nz/Southern Institute of Technology_Favicon.png', 'Invercargill, New Zealand', 'Southern Institute of Technology is a public institute known for applied and vocational education and the Zero Fees Scheme.', 'https://www.sit.ac.nz', 'Not ranked globally', '1971', '13000'),
(231, 'Southern Utah University', 'United States', '0', '0', 'Cedar City, Utah', 'Southern Utah University (SUU) is a public university offering a wide range of undergraduate and graduate programs with an emphasis on personalized, career-focused education, hands-on learning, and community engagement. Founded as a normal school in 1897, SUU has grown into a comprehensive university with more than 140 academic programs and a strong student experience that balances academics, outdoor adventure, and campus life.', 'https://www.suu.edu', '#2626 globally (EduRank 2025 global ranking)', '1897', '9468'),
(232, 'Southwestern University', 'United States', '0', '0', 'Georgetown, Texas, USA', 'Southwestern University is a private liberal arts university emphasizing academic rigor and personalized education. It offers strong programs in arts, sciences, business, and education. The university focuses on critical thinking, leadership, experiential learning, and close faculty-student engagement.', 'https://www.southwestern.edu', 'Not ranked in major global rankings', '1840', '1600'),
(233, 'St Marys University', 'united kingdom', '/catalog/University_Banner/St Marys University Banner.png', '/catalog/University_Favicon/st-marys-university_Favicon.png', 'San Antonio, Texas, USA', 'St. Mary?s University is a private Catholic university offering liberal arts and professional programs. It emphasizes ethical leadership, service learning, and academic excellence. The university is known for business, law, sciences, and humanities with a strong community-focused mission.', 'https://www.stmarytx.edu', 'Not ranked in major global rankings', '1852', '3600'),
(234, 'St. Bonaventure University', 'United States', '0', '0', 'St. Bonaventure University', 'St. Bonaventure University is a private Catholic Franciscan university founded in 1858. It offers more than 60 undergraduate programs and 21 graduate degrees, emphasizing liberal arts, career-ready education, strong community values, and a Franciscan heritage of service and learning.', 'https://www.sbu.edu', '#2436 globally (EduRank 2025)', '1858', '3,053'),
(235, 'St. Catherine University', 'United States', '0', '0', 'Saint Paul, Minnesota', 'St. Catherine University is a private Catholic university founded to provide liberal arts and professional education, originally focused on women?s education but now offering undergraduate, graduate, and adult programs. It has a strong emphasis on inclusivity, social justice, and community engagement.', 'https://www.stkate.edu', '#2281 in the world by EduRank', '1905', '3,699'),
(236, 'St. Lawrence College', 'Canada', '/catalog/University_Banner/canada-banner/St.LawrenceCollegebanner.png', '/catalog/University_Favicon/canada/St. Lawrence College Favicon.png', 'Kingston, Ontario, Canada', 'St. Lawrence College is a public college offering career-focused diploma and applied degree programs.', 'https://www.stlawrencecollege.ca', 'Not ranked globally', '1967', '8000'),
(237, 'St. Thomas Aquinas College', 'United States', '0', '0', 'Sparkill, New York', 'St. Thomas Aquinas College (often STAC) is a private liberal arts college founded by the Dominican Sisters of Sparkill. It offers undergraduate and graduate programs across schools such as Arts & Sciences, Business, Education, and STEM, with over 100 majors, minors, and specializations. The college emphasizes student success, affordability, engaged learning, and graduate outcomes, and has been nationally recognized by U.S. News & World Report and Money for its quality and social mobility efforts.', 'https://stac.edu', '#6185 in the world by EduRank', '1952', '1,950'),
(238, 'St. Thomas University', 'Canada', '/catalog/University_Banner/canada-banner/St.ThomasUniversitybanner.png', '/catalog/University_Favicon/canada/St. Thomas University Favicon.png', 'Miami Gardens, Florida, USA', 'St. Thomas University is a private Catholic university offering undergraduate and graduate programs. It emphasizes ethical leadership, social justice, and academic excellence. The university is known for business, law, education, and liberal arts programs with a diverse student population.', 'https://www.stu.edu', 'Not ranked in major global rankings', '1961', '5000'),
(239, 'Stevens Institute of Technology', 'United States', '0', '/catalog/University_Favicon/usa/Stevens Institute of Technology_Favicon.png', 'Hoboken, New Jersey', 'Stevens Institute of Technology is a private research university specializing in engineering, science, business, and technology. It is known for innovation, entrepreneurship, and strong industry connections. The university emphasizes research, hands-on learning, and career-focused education in STEM fields.', 'https://www.stevens.edu', '#621?630 in the world by QS World University Rankings', '1870', '8000'),
(240, 'Stony Brook University', 'United States', '0', '0', 'Stony Brook, New York, USA', 'Stony Brook University is a public research university and part of the SUNY system. It is internationally recognized for research in science, engineering, medicine, and technology. The university emphasizes innovation, interdisciplinary research, and global academic collaboration.', 'https://www.stonybrook.edu', '#396 in the world by QS World University Rankings', '1957', '26000'),
(241, 'Suffolk University', 'United States', '0', '0', 'Boston, Massachusetts', 'Suffolk University is a private research university founded in 1906 by Gleason L. Archer as a law school and later expanded into a comprehensive university with a College of Arts & Sciences, Sawyer Business School, and Suffolk University Law School. Suffolk emphasizes experiential learning, internships, and access to professional opportunities in Boston?s dynamic economy. It has a diverse student body and offers undergraduate, graduate, and law degree programs.', 'https://www.suffolk.edu', '#1304 in the world by EduRank', '1906', '6,403'),
(242, 'Suncrest College', 'Canada', '/catalog/University_Banner/canada-banner/NorthernLightsCollegebanner.png', '/catalog/University_Favicon/canada/Suncrest College_Favicon.png', 'Saskatchewan, Canada', 'Suncrest College is a public regional college offering vocational and skills-based education programs.', 'https://suncrestcollege.ca', 'Not ranked globally', '2021', '2000'),
(243, 'SUNY Albany', 'United States', '0', '/catalog/University_Favicon/usa/SUNY Albany_Favicon.png', 'Albany, New York, USA', 'SUNY Albany (University at Albany) is a public research university within the State University of New York system. It offers a wide range of undergraduate and graduate programs and is known for research in public policy, education, business, health sciences, and computer science.', 'https://www.albany.edu', 'Ranked ~351?400 in world lists (THE)', '1844', '17,500'),
(244, 'SUNY New Paltz', 'United States', '0', '/catalog/University_Favicon/usa/SUNY New Paltz_Favicon.png', 'New Paltz, New York', 'The State University of New York at New Paltz (SUNY New Paltz) is a public university and part of the SUNY system. It offers undergraduate and graduate programs in arts, sciences, business, education, engineering, and liberal arts, and is known for its strong creative arts and education offerings.', 'https://www.newpaltz.edu', '#1781 in the world by EduRank', '1928', '7,800'),
(245, 'SUNY Polytechnic Institute', 'United States', '0', '/catalog/University_Favicon/usa/SUNY Polytechnic Institute_Favicon.png', 'Marcy, New York', 'SUNY Polytechnic Institute (SUNY Poly) is a public polytechnic university and part of the State University of New York (SUNY) system. It focuses on technology, engineering, business, health sciences, and other fields, offering undergraduate and graduate degrees with hands-on and career-oriented programs.', 'https://sunypoly.edu', '#2140 in the world by EduRank', '1966', '2,733'),
(246, 'Swansea University', 'united kingdom', '/catalog/University_Banner/Swansea University-banner.png', '/catalog/University_Favicon/Swansea UniversityFavicon.png', 'Swansea, Wales', 'Swansea University is a public research university located in Swansea, Wales, UK, known for its waterfront campuses, strong academic and research environment, and high levels of student satisfaction. Founded in 1920, it offers a wide range of undergraduate, postgraduate, and research programs with a global outlook. The university combines high-quality teaching with impactful research and excellent graduate outcomes.', 'https://www.swansea.ac.uk', '#292 globally in the QS World University Rankings', '1920', '21,225'),
(247, 'Technological University of the Shannon (TUS) (AIT)', 'Ireland', '/catalog/University_Banner/Ireland/AthloneInstituteofTechnologybanner.png', '/catalog/University_Favicon/ireland/Technological University of the Shannon_Favicon.png', 'Athlone, Ireland', 'Technological University of the Shannon ? Athlone Campus (AIT) is a public technological university focused on applied learning.', 'https://www.tus.ie', 'Not ranked globally', '1970', '8000'),
(248, 'Technological University of the Shannon (TUS) (LIT)', 'Ireland', '/catalog/University_Banner/Ireland/LimerickInstituteof Technologybanner.png', '/catalog/University_Favicon/ireland/Technological University of the Shannon_Favicon.png', 'Limerick, Ireland', 'Technological University of the Shannon ? Limerick Campus (LIT) is a public technological university focused on applied learning and industry links.', 'https://www.tus.ie', 'Not ranked globally', '1970', '7500'),
(249, 'Teesside University', 'united kingdom', '/catalog/University_Banner/Teesside University Banner.png', '/catalog/University_Favicon/Teesside UniversityFavicon.png', 'Middlesbrough, England, UK', 'Teesside University is a public university recognized for digital innovation and applied learning. It offers programs in computing, engineering, business, health, and creative arts. The university focuses on employability, industry-aligned education, and student support. It has strong regional and international partnerships.', 'https://www.tees.ac.uk', '1001?1200 (THE)', '1930', '21000'),
(250, 'Teesside University - London Campus', 'united kingdom', '/catalog/University_Banner/Teesside University Banner.png', '/catalog/University_Favicon/Teesside UniversityFavicon.png', 'London, England, UK', 'Teesside University London is the London campus of Teesside University, offering career-focused undergraduate and postgraduate programs. It specializes in business, finance, digital technologies, and management. The campus emphasizes employability, industry relevance, and practical learning in a global city setting.', 'https://www.tees.ac.uk/london', 'Parent university #801?1000 by THE', '2015', '2000'),
(251, 'Tennessee Tech University', 'United States', '0', '/catalog/University_logo//1723020067-Tennessee%20Tech%20University_Favicon.png', 'Cookeville, Tennessee', 'Tennessee Technological University (Tennessee Tech or TTU) is a public research university and institute of technology that emphasizes hands-on learning, STEM, engineering, business, education, nursing, and liberal arts programs. It?s governed by the Tennessee Board of Regents and is classified among R2: Doctoral Universities ? High research activity. The university fosters experiential education, student research, and community engagement across a variety of academic and professional fields.', 'https://www.tntech.edu', '#1423 in the world by EduRank', '1915', '10,701'),
(252, 'Texas A and M University at Corpus Christi', 'United States', '0', '/catalog/University_logo//1723020142-Texas%20A%20-%20M%20University%20at%20Corpus%20Christi_Favicon.png', 'Corpus Christi, Texas', 'Texas A&M University?Corpus Christi (often called TAMU?CC) is a public research university and a part of the Texas A&M University System, known as ?The Island University? due to its location on Ward Island. It offers undergraduate, master?s, and doctoral programs across fields including arts, business, education, science, and technology.', 'https://tamucc.edu', '#1692 in the world by EduRank', '1947', '10,855'),
(253, 'Texas State University', 'United States', '0', '/catalog/University_Favicon/usa/Texas State University_Favicon.png', 'San Marcos, Texas, USA', 'Texas State University is a large public research university with a broad range of degree programs and active student life. It combines academic rigor with applied research and community partnerships, especially strong in business, education, and health professions. The university is noted for diversity and inclusive campus culture.', 'https://www.txstate.edu', 'Ranked #1001?1200 approx (varies by source)', '1899', '38,000'),
(254, 'The Catholic University of America', 'United States', '0', '/catalog/University_Favicon/usa/The Catholic University of America_Favicon.png', 'Washington, D.C.', 'The Catholic University of America (CUA) is a private Catholic research university ? the national university of the Catholic Church in the United States and the only institution of higher education founded by the U.S. Conference of Catholic Bishops. It combines strong academics with its Catholic identity across liberal arts, sciences, engineering, business, education, architecture, law, and theology programs. CUA has been designated an R1: Very High Research Activity university, placing it among the top research universities in the U.S.', 'https://www.catholic.edu', '#1274 in the world by CWUR', '1887', '5,366'),
(255, 'The New School', 'United States', '0', '0', 'New York City, New York, USA', 'The New School is a private university known for its progressive and interdisciplinary approach to education. It offers programs in design, social sciences, liberal arts, performing arts, and public policy. The university emphasizes creativity, social justice, and innovation in an urban global setting.', 'https://www.newschool.edu', 'Not ranked in major global rankings', '1919', '10000'),
(256, 'The University of Southern Mississippi', 'United States', '0', '/catalog/University_Favicon/usa/The University of Southern Mississippi_Favicon.png', 'Hattiesburg, Mississippi', 'The University of Southern Mississippi is a public research university offering a wide range of academic programs. It is known for strengths in education, business, arts, and marine science research. The university emphasizes student success, research opportunities, and community engagement across its campuses.', 'https://www.usm.edu', '#1400+ in the world by EduRank', '1910', '14000'),
(257, 'The University of Western Australia', 'Australia', '0', '/catalog/University_Favicon/australia/The University of Western Australia_Favicon.png', 'Perth, Western Australia, Australia', 'The University of Western Australia is a leading public research university and a member of Australia?s Group of Eight.', 'https://www.uwa.edu.au', 'Top 100 (QS)', '1911', '25000'),
(258, 'Thomas Jefferson University', 'United States', '0', '/catalog/University_logo//1723020891-Thomas%20Jefferson%20University_Favicon.png', 'Philadelphia, Pennsylvania', 'Thomas Jefferson University is a private research university based in Philadelphia, Pennsylvania, USA, known for strong professional and health-focused education with nearly 200 undergraduate, graduate, and online programs. Originating in 1824 as Jefferson Medical College and later merging with Philadelphia University in 2017, it emphasizes experiential learning and career readiness across fields like health sciences, design, business, and engineering. The university combines academic excellence with real-world experience and extensive clinical and industry connections.', 'https://www.jefferson.edu', '#450 globally in the CWUR World University Rankings', '1824', '8,315'),
(259, 'Thompson Rivers University', 'Canada', '/catalog/University_Banner/canada-banner/ThompsonRiversUniversitybanner.png', '/catalog/University_Favicon/canada/Thompson Rivers University Favicon.png', 'Kamloops, British Columbia, Canada', 'Thompson Rivers University is a public university offering undergraduate, graduate, and open learning programs. It is known for flexible learning options, career-focused education, and applied research. The university serves a diverse student population with strong regional and international engagement.', 'https://www.tru.ca', 'Not ranked in major global rankings', '1970', '26000'),
(260, 'Tiffin University', 'United States', '0', '/catalog/University_Favicon/usa/Tiffin University_Favicon.png', 'Tiffin, Ohio', 'Tiffin University is a private, nonprofit university offering undergraduate and graduate programs both on campus and online. It was founded as a commercial college and later expanded to full undergraduate and graduate degrees, with a focus on real-world readiness and community engagement. The campus community emphasizes smaller class sizes and a supportive environment, along with clubs, NCAA athletics (Division II), and experiential learning opportunities.', 'https://www.tiffin.edu', '#5539 in the world by EduRank', '1888', '3,598'),
(261, 'TOI-OHOMAI Institute of Technology', 'new Zealand', '/catalog/University_Banner/NewZealand/TOI-OHOMAIInstituteofTechnologybanner.png', '/catalog/University_Favicon/nz/TOI-OHOMAI Institute of Technology_Favicon.jpg', 'Tauranga & Rotorua, New Zealand', 'Toi Ohomai Institute of Technology is a public institute focused on applied and vocational education.', 'https://www.toiohomai.ac.nz', 'Not ranked globally', '2016', '14000'),
(262, 'Towson University', 'United States', '0', '/catalog/University_logo//1723021529-Towson%20University_Favicon.png', 'Towson, Maryland', 'Towson University is a public university located in Towson, Maryland, USA, about 8 miles north of Baltimore. Founded in 1866 as the Maryland State Normal School, it has grown into a comprehensive institution offering 110+ undergraduate majors, graduate and doctoral programs with strong emphasis on experiential learning, research, and community engagement. Towson has a diverse student community and a vibrant campus life with NCAA Division I athletics.', 'https://www.towson.edu', '#1115 globally in the EduRank World University Rankings', '1866', '19,401'),
(263, 'Trent University', 'Canada', '/catalog/University_Banner/canada-banner/TrentUniversitybanner.png', '/catalog/University_Favicon/canada/Trent UniversityFavicon.png', 'Peterborough, Ontario, Canada', 'Trent University is a public university known for its strong liberal arts foundation and interdisciplinary education. It offers undergraduate and graduate programs with strengths in environmental science, humanities, social sciences, and Indigenous studies. The university emphasizes small class sizes, research, and community engagement.', 'https://www.trentu.ca', '#801?1000 in the world by THE World University Rankings', '1964', '10000'),
(264, 'Trinity Christian College', 'United States', '0', '0', 'Palos Heights, Illinois', 'Trinity Christian College is a private Christian liberal arts college offering bachelor?s and select graduate programs across fields like education, business, nursing, and the arts, with a focus on faith-based learning and community engagement.', 'https://www.trnty.edu', '#5305 in the world by EduRank', '1959', '908'),
(265, 'Trinity College Dublin', 'Ireland', '/catalog/University_Banner/Ireland/TrinityCollegeDublinbanner.png', '/catalog/University_Favicon/ireland/Trinity College Dublin_Favicon.png', 'Dublin, Dublin', 'Trinity College Dublin (The University of Dublin) is a prestigious public research university located in the heart of Dublin, Ireland?s capital city. Founded in 1592, it is Ireland?s oldest and highest-ranked university, known for its strong research output, global reputation, and wide range of undergraduate and postgraduate programmes across arts, sciences, business, engineering, and health. Trinity combines historic campus architecture with modern facilities and a vibrant international student community.', 'https://www.tcd.ie', 'QS World University Rankings 2026: #75', '1592', '22000'),
(266, 'Tu Dublin', 'Ireland', '/catalog/University_Banner/Ireland/TuDublin(Tallaght)banner.png', '/catalog/University_Favicon/ireland/Tu Dublin Tallaght_Favicon.png', 'Dublin, Ireland', 'Technological University Dublin (TU Dublin) is Ireland?s largest technological university offering industry-focused programs.', 'https://www.tudublin.ie', 'Top 1000 (QS)', '2019', '28000'),
(267, 'Tulane University', 'United States', '0', '/catalog/University_Favicon/usa/Tulane University_Favicon.png', 'New Orleans, Louisiana', 'Tulane University (officially Tulane University of Louisiana) is a private research university and member of the Association of American Universities, recognized for very high research activity (R1). It offers a broad range of undergraduate, graduate, and professional programs in fields such as business, law, medicine, public health, liberal arts, engineering, and social sciences, integrating rigorous academics with experiential and community engagement.', 'https://tulane.edu', '#443 in the world by CWUR', '1834', '14,000'),
(268, 'Ulster University - Birmingham Campus', 'united kingdom', '0', '/catalog/University_Favicon/UlsterUniversity(LondonCampusandBirminghamCampus)Favicon.png', 'Birmingham, England, UK', 'Ulster University Birmingham Campus offers postgraduate programs in business, finance, and management.', 'https://www.ulster.ac.uk', '601?650 (QS)', '1868', '500'),
(269, 'Ulster University - London Campus', 'united kingdom', '/catalog/University_Banner/Ulster University (London Campus and Birmingham Campus)   Banner.png', '/catalog/University_Favicon/UlsterUniversity(LondonCampusandBirminghamCampus)Favicon.png', 'London, England, UK', 'Ulster University London Campus delivers business and technology programs from Ulster University in Northern Ireland.', 'https://www.ulster.ac.uk', '601?650 (QS)', '1868', '1000'),
(270, 'Ulster University - Manchester Campus', 'united kingdom', '/catalog/University_Banner/De Montfort University-banner.png', '/catalog/University_Favicon/DeMontfortUniversityFavicon.png', 'Manchester, England, UK', 'Ulster University ? Manchester Campus offers postgraduate programs in business, finance, and data analytics.', 'https://www.ulster.ac.uk', '601?650 (QS)', '1868', '1000');
INSERT INTO `university` (`id`, `name`, `country`, `banner_image`, `logo_image`, `city`, `description`, `link`, `ranking`, `established_year`, `enroll_students`) VALUES
(271, 'Unitec Institute of Technology', 'new Zealand', '/catalog/University_Banner/NewZealand/UnitedInstituteofTechnologybanner.png', '/catalog/University_Favicon/nz/Unitec Institute of Technology_Favicon.png', 'Auckland, New Zealand', 'Unitec Institute of Technology is a public institute offering applied education in engineering, business, and health sciences.', 'https://www.unitec.ac.nz', 'Not ranked globally', '1976', '13000'),
(272, 'United Kingdom Enquiry', 'united kingdom', '0', '/catalog/University_logo//1734339187-Enquiry_Favicon.png', 'United Kingdom', 'United Kingdom Enquiry is an education consultancy providing guidance for UK university admissions.', 'Not applicable', 'Not applicable', 'Not applicable', ''),
(273, 'University at Buffalo', 'United States', '0', '0', 'Buffalo, New York', 'University at Buffalo is a major public research university and the largest campus in the SUNY system. It offers extensive undergraduate, graduate, and professional programs and is known for strong research output in engineering, medicine, business, and sciences. The university has a global reputation for innovation and interdisciplinary research.', 'https://www.buffalo.edu', '#388 in the world by QS World University Rankings', '1846', '32000'),
(274, 'University Centre Leeds', 'United Kingdom', '0', '0', 'Leeds, England, UK', 'University Centre Leeds is a higher education provider offering undergraduate and postgraduate programs validated by UK universities. It focuses on business, digital, education, and professional studies. The centre emphasizes employability, flexible learning, and strong links with local employers.', 'https://www.ucleeds.ac.uk', 'Not ranked in major global rankings', '2009', '3000'),
(275, 'University College Birmingham', 'united kingdom', '/catalog/University_Banner/University College Birmingham Banner.png', '/catalog/University_Favicon/UniversityCollege BirminghamFavicon.png', 'Birmingham, England', 'University College Birmingham (UCB) is a public university in Birmingham, England, UK, known for career-focused and vocational higher education with strong industry links. It offers undergraduate and postgraduate degrees in fields like hospitality, tourism, business, culinary arts, sport, and health sciences, with an emphasis on hands-on learning and employability.', 'https://www.ucb.ac.uk', '#8073 in the world (EduRank 2025)', '1957', '7500'),
(276, 'University College Cork', 'Ireland', '/catalog/University_Banner/Ireland/UniversityCollegeCorkbanner.png', '/catalog/University_Favicon/ireland/University College Cork_Favicon.png', 'Cork, Ireland', 'University College Cork (UCC) is a major public research university known for excellence in arts, sciences, business, and health sciences. It combines a strong research culture with global partnerships and a focus on sustainability. UCC offers a wide range of undergraduate and postgraduate programs and has a vibrant student community.', 'https://www.ucc.ie', '#273 in the world by QS World University Rankings', '1845', '21,000'),
(277, 'University College Dublin ', 'Ireland', '/catalog/University_Banner/Ireland/UniversityCollegeDublinbanner.png', '/catalog/University_Favicon/ireland/University College Dublin_Favicon.png', 'Dublin, Ireland', 'University College Dublin (UCD) is a major public research university located in Dublin, Ireland. It?s one of Ireland?s oldest and largest universities, known for strong academic programs, research output, and global engagement. UCD offers a wide range of undergraduate and postgraduate degrees with a focus on innovation, sustainability, and employability. The campus sits in the Belfield area of Dublin and serves a diverse international student body.', 'https://www.ucd.ie', '#118 globally (QS World University Rankings 2026)', '1854', '37,000'),
(278, 'University for the Creative Arts', 'united kingdom', '/catalog/University_Banner/University for the Creative Arts Banner.png', '/catalog/University_Favicon/University for the Creative ArtsFavicon.png', 'Farnham & Canterbury, England, UK', 'University for the Creative Arts is a specialist public university focused on art, design, fashion, media, and architecture. It offers highly creative and industry-aligned programs. The university emphasizes practice-based learning and professional development. It has strong links with the global creative industries.', 'https://www.uca.ac.uk', 'Not ranked globally', '2005', '6500'),
(279, 'University of Aberdeen', 'united kingdom', '/catalog/University_Banner/University of Aberdeen Banner.png', '/catalog/University_Favicon/UniversityofAberdeenFavicon.png', 'Aberdeen, Scotland', 'The University of Aberdeen is a public research university in Aberdeen, Scotland, UK, and one of the oldest universities in the English-speaking world (founded in 1495). It offers a broad range of undergraduate, postgraduate, and doctoral programmes with strong research, especially in areas like medicine, law, engineering, and the sciences. The university is known for its historic campus, global outlook, and research excellence.', 'https://www.abdn.ac.uk', '#262 (QS World University Rankings 2026)', '1495', '12211'),
(280, 'University of Alabama - Tuscaloosa', 'United States', '0', '/catalog/University_Favicon/usa/University of Alabama - Tuscaloosa_Favicon.png', 'Tuscaloosa, Alabama, USA', 'The University of Alabama is a public research university and flagship of the Alabama system. It offers a wide range of undergraduate and graduate programs and is known for business, engineering, law, and communications. The university emphasizes research growth, innovation, and a vibrant campus culture.', 'https://www.ua.edu', '#901?950 in the world by QS World University Rankings', '1831', '38000'),
(281, 'University of Alabama at Birmingham', 'United States', '0', '0', 'Birmingham, Alabama', 'University of Alabama at Birmingham is a public research university recognized for excellence in health sciences and biomedical research. It offers comprehensive academic programs across medicine, nursing, engineering, business, and liberal arts. UAB is known for its strong research funding, innovation, and impact on healthcare and community development.', 'https://www.uab.edu', '#651?700 in the world by QS World University Rankings', '1969', '22500'),
(282, 'University of Alaska Fairbanks', 'United States', '0', '0', 'Fairbanks, Alaska, USA', 'University of Alaska Fairbanks (UAF) is a public research university and the flagship campus of the University of Alaska system. It offers programs strong in Arctic research, engineering, environmental sciences, and education. UAF supports extensive field research and global partnerships focused on northern and climate studies.', 'https://www.uaf.edu', 'Not in top global rankings', '1917', '7200'),
(283, 'University of Arizona', 'United States', '0', '/catalog/University_Favicon/usa/University of Arizona_Favicon.png', 'Tucson, Arizona, USA', 'University of Arizona is a major public research university known for innovation and interdisciplinary research. It offers a wide range of undergraduate, graduate, and professional programs, with strong strengths in engineering, business, health sciences, and astronomy. The university emphasizes research impact, global engagement, and experiential learning.', 'https://www.arizona.edu', '#262 in the world by QS World University Rankings', '1885', '47000'),
(284, 'University of Bath', 'united kingdom', '0', '/catalog/University_logo/University of Bath.jpg', 'Bath, England, UK', 'University of Bath is a leading public research university recognized for academic excellence and strong industry links. It is well known for engineering, management, sciences, and social sciences, with a strong emphasis on placements and employability. The university consistently ranks among the top universities in the UK and globally.', 'https://www.bath.ac.uk', '#148 in the world by QS World University Rankings', '1966', '19000'),
(285, 'University of Bedfordshire', 'united kingdom', '/catalog/University_Banner/University of Bedfordshire Banner.png', '/catalog/University_Favicon/UniversityofBedfordshireFavicon.png', 'Luton, England, UK', 'University of Bedfordshire is a public university with a focus on career-oriented education and applied research. It offers a wide range of programs in business, health, computing, and the creative arts. The university promotes strong industry partnerships and practical placements for student employability.', 'https://www.beds.ac.uk', '#801?1000 in the world by THE World University Rankings', '2006', '18000'),
(286, 'University of Birmingham', 'united kingdom', '0', '/catalog/University_Favicon/University of Birmingham_Favicon.png', 'Birmingham, England, UK', 'University of Birmingham is a leading public research university and a founding member of the Russell Group. It is internationally recognized for research excellence across sciences, engineering, medicine, business, and humanities. The university emphasizes innovation, global impact, and academic leadership. It has a strong international reputation.', 'https://www.birmingham.ac.uk', 'Top 100 (QS)', '1900', '35000'),
(287, 'University of Birmingham Dubai', 'united arab emirates', '0', '/catalog/University_Favicon/dubai/University Of Birmingham Dubai_Favicon.png', 'Dubai, United Arab Emirates', 'University of Birmingham Dubai is the international campus of the University of Birmingham, a leading UK research university. It delivers UK-accredited programs in business, engineering, computer science, and education. The campus emphasizes global employability, research-led teaching, and international student experience.', 'https://www.birmingham.ac.uk/dubai', 'Not ranked separately (parent university #84 QS)', '2018', '2500'),
(288, 'University of Bradford', 'united kingdom', '/catalog/University_Banner/University of Bradford Banner.png', '/catalog/University_Favicon/UniversityofBradfordFavicon.png', 'Bradford, England, UK', 'University of Bradford is a public research university with strengths in technology, management, health sciences, and social sciences. It emphasizes applied research, social inclusion, and sustainability. The university maintains strong industry and professional connections to support student careers.', 'https://www.bradford.ac.uk', '#801?1000 in the world by THE World University Rankings', '1966', '10000'),
(289, 'University of Bridgeport', 'United States', '0', '/catalog/University_Favicon/usa/University of Bridgeport_Favicon.png', 'Bridgeport, Connecticut', 'The University of Bridgeport is a private nonprofit university offering more than 60 undergraduate, graduate, and doctoral programs across fields like health sciences, engineering, business, education, arts, and sciences. It emphasizes global engagement and has students from over 80 countries.', 'https://www.bridgeport.edu', '#2362 in the world by EduRank', '1927', '5,434'),
(290, 'University of Brighton', 'united kingdom', '/catalog/University_Banner/University of Brighton    banner.png', '/catalog/University_Favicon/UniversityofBrightonFavicon.png', 'Brighton, England', 'The University of Brighton is a public university based in Brighton, England, UK, known for its practical, professional and creative programmes across arts, engineering, business, health sciences and more. Its origins date back to the Brighton School of Art in 1858, and it gained full university status in 1992. The university has multiple campuses in and around Brighton and supports a diverse student community with an emphasis on real-world skills and employability.', 'https://brighton.ac.uk', '#893 globally (EduRank World University Rankings)', '1858', '18,000'),
(291, 'University of Bristol', 'united kingdom', '/catalog/University_Banner/University of Bristol Banner.png', '/catalog/University_Favicon/University of Bristol_Favicon.png', 'Bristol, England, UK', 'University of Bristol is a prestigious public research university and member of the Russell Group. It is globally recognized for excellence in research, innovation, and teaching across engineering, sciences, health, arts, and social sciences. The university attracts a diverse international student community.', 'https://www.bristol.ac.uk', '#55 in the world by QS World University Rankings', '1876', '27000'),
(292, 'University of Canada West', 'Canada', '/catalog/University_Banner/canada-banner/UniversityofCanadaWestbanner.png', '/catalog/University_Favicon/canada/University of Canada West Favicon.png', 'Vancouver, British Columbia, Canada', 'University of Canada West is a private, career-focused university offering undergraduate and graduate programs. It is known for business, management, and leadership education with a strong emphasis on practical skills. The university emphasizes small class sizes, industry-relevant curriculum, and preparing students for professional careers.', 'https://www.ucanwest.ca', 'Not ranked in major global rankings', '2004', '13000'),
(293, 'University of Canterbury', 'new Zealand', '/catalog/University_Banner/NewZealand/University of Canterburybanner.png', '/catalog/University_Favicon/nz/University of Canterbury_Favicon.png', 'Christchurch, New Zealand', 'University of Canterbury is a major public research university known for engineering and science programs.', 'https://www.canterbury.ac.nz', 'Top 300 (QS)', '1873', '18000'),
(294, 'University of Central Lancashire', 'united kingdom', '/catalog/University_Banner/University of Central Lancashire banner.png', '/catalog/University_Favicon/University of Central LancashireFavicon.png', 'Preston, Lancashire, England', 'The University of Central Lancashire (UCLan) is a major public university based in Preston, England, with roots dating back to 1828 when it began as the Institution for the Diffusion of Knowledge. It offers a wide range of undergraduate and postgraduate programs focusing on practical skills, research impact, and employability for students from over 100 countries. UCLan has modern campuses, strong industry links, and a vibrant student community of around 38,000. The university is known for its applied research and commitment to community engagement across the UK and internationally.', 'https://www.uclan.ac.uk', '#1460 globally (CWUR)', '1828', '38,000'),
(295, 'University of Charleston', 'United States', '0', '0', 'Charleston, West Virginia', 'The University of Charleston (UC) is a private co-educational university established in 1888. It offers associate, bachelor?s, master?s, and professional programs across arts & sciences, business, health sciences (including physician assistant and nursing programs), leadership, and more, with strong emphasis on career readiness, innovation, and student outcomes. The main campus is in Charleston, with a secondary location in Beckley, West Virginia. UC is accredited by the Higher Learning Commission.', 'https://www.ucwv.edu', '#3904 in the world by EduRank', '1888', '3,032'),
(296, 'University of Chester', 'united kingdom', '/catalog/University_Banner/university of chester  banner (1).png', '/catalog/University_Favicon/University of ChesterFavicon.png', 'Chester, England, UK', 'University of Chester is a public university offering a wide range of undergraduate and postgraduate programs. It is known for its supportive learning environment, strong student satisfaction, and career-focused education. The university has historic campuses and emphasizes employability and professional practice.', 'https://www.chester.ac.uk', '#1201?1500 in the world by THE World University Rankings', '1839', '15000'),
(297, 'University of Colorado Denver', 'United States', '0', '/catalog/University_Favicon/usa/University of Colorado Denver_Favicon.png', 'Denver, Colorado', 'The University of Colorado Denver (often called CU Denver) is a public research university and part of the University of Colorado system. It offers more than 100 bachelor?s, master?s, and doctoral programs and is classified among R1 research universities (very high research activity). It is located on the urban Auraria Campus in downtown Denver.', 'https://www.ucdenver.edu', '#851 in the world by QS World University Rankings', '1912', '13,853'),
(298, 'University of Dayton', 'United States', '0', '/catalog/University_Favicon/usa/University of Dayton_Favicon.png', 'Dayton, Ohio, USA', 'University of Dayton is a private Catholic research university with strong programs in engineering, business, education, and sciences. It emphasizes experiential learning, research, and community engagement rooted in Marianist values. The university is known for student support, innovation, and ethical leadership.', 'https://udayton.edu', '#901?950 in the world by QS World University Rankings', '1850', '11500'),
(299, 'University of Derby', 'united kingdom', '/catalog/University_Banner/University of Derby _Banner.png', '/catalog/University_Favicon/University of Derby_Favicon.png', 'Derby, England, UK', 'University of Derby is a public university offering career-focused undergraduate and postgraduate programs. It is known for strong industry links in business, engineering, health, and creative industries. The university emphasizes employability, applied research, and modern learning facilities.', 'https://www.derby.ac.uk', '#1001?1200 in the world by THE World University Rankings', '1851', '20000'),
(300, 'University of Dubuque', 'United States', '0', '0', 'Dubuque, Iowa, USA', 'University of Dubuque is a private university offering programs in business, theology, and applied sciences.', 'https://www.dbq.edu', 'Not ranked globally', '1852', '2000'),
(301, 'University of Dundee', 'united kingdom', '/catalog/University_Banner/University of Dundee   Banner.png', '/catalog/University_Favicon/University of DundeeFavicon.png', 'Dundee, Scotland', 'The University of Dundee is a public research university known for strong teaching, internationally-focused research, and high student satisfaction across a wide range of subjects including life sciences, medicine, law, engineering, and the arts. It became an independent university with its own Royal Charter in 1967, having roots dating back to 1881.', 'https://www.dundee.ac.uk', '#428 in the world by QS World University Rankings', '1881', '14,385'),
(302, 'University of East Anglia', 'united kingdom', '/catalog/University_Banner/University of East Anglia   Banner.png', '/catalog/University_Favicon/University of East AngliaFavicon.png', 'Norwich, England, UK', 'University of East Anglia is a leading public research university and a member of major research networks. It is known for excellence in environmental sciences, creative writing, business, and social sciences. The university emphasizes research impact, high-quality teaching, and global engagement. It has a strong international academic reputation.', 'https://www.uea.ac.uk', 'Top 300 (QS)', '1963', '18000'),
(303, 'University of East London', 'united kingdom', '/catalog/University_Banner/University of East London Banner.png', '/catalog/University_Favicon/University of East LondonFavicon.png', 'London, England, UK', 'University of East London is a public university with a strong mission of social mobility and applied education. It offers programs in business, law, health, engineering, and social sciences. The university emphasizes employability, sustainability, and community impact. It operates modern campuses in East London.', 'https://www.uel.ac.uk', '1001?1200 (THE)', '1898', '17000'),
(304, 'University of Essex', 'united kingdom', '/catalog/University_Banner/University of Essex   Banner.png', '/catalog/University_Favicon/University of EssexFavicon.png', 'Colchester, England, UK', 'University of Essex is a public research university known for social sciences, data analytics, and human rights.', 'https://www.essex.ac.uk', '401?450 (QS)', '1964', '15000'),
(305, 'University of Exeter', 'united kingdom', '/catalog/University_Banner/University of Exeter Banner.png', '/catalog/University_Favicon/University of ExeterFavicon.png', 'Exeter, England, UK', 'University of Exeter is a public research university known for business, environmental science, and humanities.', 'https://www.exeter.ac.uk', 'Top 150 (QS)', '1955', '30000'),
(306, 'University of Galway', 'Ireland', '/catalog/University_Banner/Ireland/NationalUniversityofIrelandGalwaybanner.png', '/catalog/University_Favicon/ireland/National University of Ireland Galway_Favicon.png', 'Galway, Ireland', 'University of Galway is a public research university with a history dating back to 1845. It offers a wide range of programs, strong research output, and international collaborations. The university is ranked in the top ~300 globally by QS and emphasises sustainability, innovation, and global engagement.', 'https://universityofgalway.ie', '#284 in the world by QS Rankings', '1845', '19,335'),
(307, 'University of Glasgow', 'united kingdom', '0', '/catalog/University_logo/University of Glasgow.jpg', 'Glasgow, Scotland', 'The University of Glasgow is a public research university and one of the oldest universities in the English-speaking world, founded in 1451. It?s a member of the prestigious Russell Group of leading UK research universities and is known globally for excellence in teaching, research impact, and international outlook.', 'https://www.gla.ac.uk', '#79 in the QS World University Rankings', '1451', '35,600'),
(308, 'University of Gloucestershire', 'united kingdom', '0', '/catalog/University_Favicon/University of Gloucestershire_Favicon.png', 'Cheltenham, England', 'The University of Gloucestershire is a public university offering a broad range of undergraduate and postgraduate programmes with a strong focus on professional development, applied learning, and student experience. It has developed a reputation for practical teaching, supportive community environments, and continuous improvement across academic and subject rankings in the UK.', 'https://www.glos.ac.uk', '#1981 :EduRank Global Ranking 2025', '1834', '7835'),
(309, 'University of Greenwich', 'united kingdom', '/catalog/University_Banner/University of Greenwich_Banner.jpg', '/catalog/University_Favicon/University Of Greenwich_Favicon.png', 'London & Greenwich, England, UK', 'University of Greenwich is a public university offering a wide array of programs across business, engineering, humanities, and sciences. It has historic campuses and strong professional links in arts, architecture, education, and maritime studies. The university emphasizes practical learning and global opportunities.', 'https://www.gre.ac.uk', '#801?1000 in the world by THE World University Rankings', '1890', '20000'),
(310, 'University of Hartford', 'United States', '0', '/catalog/University_logo//1723021659-University%20of%20Hartford_Favicon.png', 'West Hartford, Connecticut', 'The University of Hartford is a private university in West Hartford, Connecticut, USA, offering a wide range of undergraduate and graduate programs with a focus on career-oriented education, performing arts, engineering, and business. It was formed in 1957 through a federation of colleges and is known for small class sizes and a campus that spans into neighboring Hartford and Bloomfield. UHart emphasizes practical learning, internships, and global perspectives for its students.', 'https://www.hartford.edu', '#1577 globally in the 2025 EduRank World University Rankings', '1957', '6000'),
(311, 'University of Hertfordshire', 'united kingdom', '/catalog/University_Banner/University of Hertfordshire banner.png', '/catalog/University_Favicon/University of HertfordshireFavicon.png', 'Hatfield, England, UK', 'University of Hertfordshire is a large public university offering career-focused academic programs. It is known for strengths in business, engineering, health sciences, computing, and creative fields. The university emphasizes placements, industry collaboration, and modern learning facilities. It hosts a diverse international student community.', 'https://www.herts.ac.uk', '801?1000 (QS)', '1952', '32000'),
(312, 'University of Huddersfield - London', '', '0', '/catalog/University_logo//1741243165-University-of-Huddersfield---London_Favicon.png', 'London, England, UK', 'University of Huddersfield ? London Campus delivers business and management programs from the University of Huddersfield.', 'https://www.hud.ac.uk', 'Top 600 (QS)', '1825', '1500'),
(313, 'University of Hull - London', 'united kingdom', '0', '/catalog/University_Favicon/University of Hull_Favicon.png', 'London, England, UK', 'University of Hull ? London Campus offers business, logistics, and management programs in partnership delivery.', 'https://www.hull.ac.uk', 'Top 500 (QS)', '1927', '1000'),
(314, 'University of Illinois Chicago', 'United States', '0', '/catalog/University_Favicon/usa/University of Illinois Chicago_Favicon.png', 'Chicago, Illinois, USA', 'University of Illinois Chicago is a major public research university and part of the University of Illinois system. It offers comprehensive undergraduate, graduate, and professional programs with strong research activity. The university is known for health sciences, engineering, business, and urban-focused research and innovation.', 'https://www.uic.edu', '#323 in the world by QS World University Rankings', '1982', '34000'),
(315, 'University of Illinois Springfield', 'United States', '0', '/catalog/University_Favicon/usa/University of Illinois Springfield_Favicon.png', 'Springfield, Illinois, USA', 'University of Illinois Springfield is a public university known for public affairs, liberal arts, and professional studies. It emphasizes small class sizes, applied learning, and strong faculty-student interaction. The university integrates research, internships, and community engagement into its academic programs.', 'https://www.uis.edu', 'Not ranked in major global rankings', '1969', '4000'),
(316, 'University of Kansas', 'United States', '0', '0', 'Lawrence, Kansas', 'The University of Kansas (KU) is a public research university located in Lawrence, Kansas, USA. Founded in 1865, it is the state?s flagship institution and a member of the Association of American Universities (AAU). KU offers a wide range of undergraduate, graduate, and professional programs and is especially known for its strengths in research, health sciences, engineering, business, and liberal arts. The university combines strong academics with an active campus and athletic culture.', 'https://www.ku.edu', '#465 QS World University 2026', '1866', '27625'),
(317, 'University of Kent', 'united kingdom', '0', '/catalog/University_Favicon/University of Kent_Favicon.png', 'Canterbury, Kent, England', 'The University of Kent is a public research university in Canterbury and Medway, England, UK, known for its research-led teaching, international outlook, and vibrant student community. Founded in 1965, it offers a wide range of undergraduate and postgraduate programs across arts, sciences, social sciences and professional fields, with strong emphasis on employability and real-world experience. Its campuses combine modern facilities with historic surroundings and active student life.', 'https://www.kent.ac.uk', '#405 globally in the EduRank World University Rankings', '1965', '18,395'),
(318, 'University of Law', 'united kingdom', '/catalog/University_Banner/University of Law banner.png', '/catalog/University_Favicon/University of LawFavicon.png', 'London & Multiple Cities, UK', 'University of Law is a private university specializing in legal education and professional training. It offers undergraduate, postgraduate, and professional law and business programs. The university is closely aligned with legal practice and professional bodies. It emphasizes practical skills, employability, and career preparation.', 'https://www.law.ac.uk', 'Not ranked globally', '1876', '16000'),
(319, 'University of Leeds', 'united kingdom', '/catalog/University_Banner/University of Leeds Banner.png', '/catalog/University_Favicon/University of LeedsFavicon.png', 'Leeds, England', 'The University of Leeds is a public research university located in Leeds, West Yorkshire, England, UK. It is a member of the prestigious Russell Group of research-intensive universities and offers a wide range of undergraduate, postgraduate, and doctoral programmes with strong global research impact, industry engagement, and international collaboration. The university is known for its academic excellence, vibrant campus life, and diverse international community.', 'https://www.leeds.ac.uk', '#86 (QS World University Rankings 2026)', '1904', '39000'),
(320, 'University of Leicester', 'united kingdom', '/catalog/University_Banner/University of Leicester   Banner.png', '/catalog/University_Favicon/University of LeicesterFavicon.png', 'Leicester, England', 'The University of Leicester is a public research university in Leicester, England, United Kingdom. Founded as a civic memorial to those who died in World War I, it is known for strong research output, international collaborations, and a wide range of undergraduate and postgraduate programmes. Leicester has a dynamic campus environment with particular strengths in areas such as medicine, archaeology (including work on Richard III), space science, and social sciences.', 'https://le.ac.uk', '#326 (QS World University Rankings 2026)', '1921', '14825'),
(321, 'University of Limerick', 'Ireland', '/catalog/University_Banner/Ireland/UniversityofLimerickbanner.png', '/catalog/University_Favicon/ireland/University of Limerick_Favicon.png', 'Limerick, Ireland', 'University of Limerick is a modern public university recognized for its experiential learning and industry collaboration. It offers strong programs in engineering, business, health sciences, and computing. The campus features cutting-edge facilities with a focus on co-operative education, internships, and research impact.', 'https://www.ul.ie', '#401?450 in the world by THE World University Rankings', '1972', '18,000'),
(322, 'University of Lincoln', 'united kingdom', '0', '/catalog/University_Favicon/University of Lincoln_Favicon.png', 'Lincoln, Lincolnshire, England', 'The University of Lincoln is a public research university known for its modern, student-centred campus and commitment to quality teaching and research. It has grown rapidly since gaining university status in 1992 and has become internationally recognised for innovative academic programs, strong industry links, sustainability initiatives, and high student satisfaction. Citations and research excellence are increasingly notable, and its graduations take place in historic Lincoln Cathedral.', 'https://www.lincoln.ac.uk', '#801 by QS World University Rankings', '1992', '15,000'),
(323, 'University of Liverpool', 'united kingdom', '/catalog/University_Banner/University of Liverpool Banner.jpg', '/catalog/University_Favicon/University of Liverpool_Favicon.png', 'Liverpool, England', 'The University of Liverpool is a public research university and a founding member of the prestigious Russell Group. Known for its strong research output, academic reputation, and global outlook, it offers a wide range of undergraduate and postgraduate programs across sciences, engineering, medicine, arts, social sciences, and more.', 'https://www.liverpool.ac.uk', '#147 in the QS World University Rankings', '1881', '31,000'),
(324, 'University of Manchester', 'united kingdom', '0', '/catalog/University_Favicon/University of Manchester_Favicon.png', 'Manchester, England, UK', 'University of Manchester is a leading public research university and a major member of the Russell Group.', 'https://www.manchester.ac.uk', 'Top 50 (QS)', '1824', '40000'),
(325, 'University of Mary Hardin - Baylor', 'United States', '0', '/catalog/University_logo//1723020208-University%20of%20Mary%20Hardin%20-%20Baylor_Favicon_Favicon.png', 'Belton, Texas', 'The University of Mary Hardin-Baylor (UMHB) is a private, nonprofit Christian university offering undergraduate, graduate, and doctoral programs. Founded as an educational institution in 1845, it?s one of the oldest colleges in Texas. UMHB emphasizes liberal arts, nursing, business, education, and sciences with a focus on faith-based learning and community engagement.', 'https://www.umhb.edu', '#1076 in the United States by EduRank', '1845', '3,520'),
(326, 'University of Maryland, Baltimore County', 'United States', '0', '/catalog/University_Favicon/usa/University of Maryland, Baltimore County_Favicon.png', 'Baltimore County, Maryland, USA', 'University of Maryland, Baltimore County is a public research university known for STEM excellence and innovation. It offers strong programs in engineering, computer science, sciences, and social sciences. The university emphasizes research, inclusive excellence, and strong outcomes for student success.', 'https://www.umbc.edu', '#701?750 in the world by QS World University Rankings', '1966', '14000'),
(327, 'University of Massachusetts Boston', 'United States', '0', '/catalog/University_Favicon/usa/University of Massachusetts Boston_Favicon.png', 'Boston, Massachusetts, USA', 'University of Massachusetts Boston is a public research university and part of the UMass system. It offers a wide range of undergraduate and graduate programs with strengths in business, public policy, health sciences, and liberal arts. The university emphasizes urban engagement, research impact, and diversity in a metropolitan setting.', 'https://www.umb.edu', '#1001?1200 in the world by THE World University Rankings', '1964', '16000'),
(328, 'University of Massachusetts, Amherst', 'United States', '0', '/catalog/University_logo//1723020968-University%20of%20Massachusetts-%20Amherst_Favicon.png', 'Amherst, Massachusetts, USA', 'University of Massachusetts Amherst is the flagship public research university of the UMass system. It is known for strong research output and programs in engineering, business, sciences, and social sciences. The university emphasizes innovation, sustainability, and global academic collaboration.', 'https://www.umass.edu', '#245 in the world by QS World University Rankings', '1863', '32000'),
(329, 'University of Nebraska Omaha', 'United States', '0', '/catalog/University_logo//1723021738-University%20of%20Nebraska%20Omaha_Favicon.png', 'Omaha, Nebraska, USA', 'University of Nebraska Omaha is a public research university known for community engagement and applied research. It offers strong programs in business, engineering, public administration, education, and sciences. The university emphasizes experiential learning, internships, and partnerships with local industries.', 'https://www.unomaha.edu', '#1201?1500 in the world by THE World University Rankings', '1908', '15000'),
(330, 'University of Nevada at Reno', 'United States', '0', '/catalog/University_Favicon/usa/University of Nevada at Reno_Favicon.png', 'Reno, Nevada', 'The University of Nevada, Reno (UNR) is a public land-grant research university and the flagship institution of the Nevada System of Higher Education. Founded in 1874 as the first institution of higher education in Nevada, UNR offers a broad range of undergraduate, graduate, and professional degrees across disciplines such as engineering, business, mining, journalism, agriculture, environmental science, and health sciences. UNR conducts research across numerous fields, has a medical school, and is classified as a Carnegie R1 research university, indicating very high research activity.', 'https://www.unr.edu', '#706 in the world by CWUR', '1874', '20,945'),
(331, 'University of New England - USA', 'United States', '0', '0', 'Biddeford, Maine', 'The University of New England (UNE) is a private research university with additional campuses in Portland, Maine, and a study-abroad site in Tangier, Morocco. It offers a wide range of undergraduate, graduate, online, and professional programs ? including the state?s only medical, dental, and pharmacy colleges ? and is known for hands-on learning, strong health and science programs, and community engagement.', 'https://www.une.edu', '#2138 in the world by EduRank', '1831', '5,924'),
(332, 'University of New Hampshire', 'United States', '0', '/catalog/University_Favicon/usa/University of New Hampshire_Favicon.png', 'Durham, New Hampshire, USA', 'University of New Hampshire is a public research university and the flagship institution of the state. It offers comprehensive academic programs with strengths in engineering, business, health sciences, and environmental studies. The university emphasizes research, sustainability, and experiential learning.', 'https://www.unh.edu', '#801?1000 in the world by THE World University Rankings', '1866', '15000'),
(333, 'University of New Haven', 'United States', '0', '/catalog/University_Favicon/usa/University of New Haven_Favicon.png', 'West Haven, Connecticut', 'University of New Haven is a private university known for its strong focus on experiential learning and career-oriented education. It offers a wide range of undergraduate and graduate programs, especially recognized for forensic science, engineering, business, and criminal justice. The university emphasizes internships, research, and hands-on training to prepare students for professional success.', 'https://www.newhaven.edu', '#1781 in the world by EduRank', '1920', '9,229'),
(334, 'University of New Mexico', 'United States', '0', '/catalog/University_Favicon/usa/University of New Mexico_Favicon.png', 'Albuquerque, New Mexico', 'The University of New Mexico (UNM) is a public research university and the flagship institution of the state. It offers undergraduate, graduate, and professional programs across 12 colleges and schools, including a medical school and the only law school in New Mexico. UNM is classified as an R1: Doctoral University with very high research activity and serves a diverse student body.', 'https://www.unm.edu', '#187 in the world by EduRank', '1889', '23,955'),
(335, 'University of Niagara Falls Canada', 'Canada', '0', '/catalog/University_Favicon/canada/University of Niagara Falls Canada_Favicon.png', 'Niagara Falls, Ontario, Canada', 'University of Niagara Falls Canada is a private university offering programs in business, technology, and digital innovation.', 'https://www.unfc.ca', 'Not ranked globally', '2022', '1500'),
(336, 'University of North Alabama', 'United States', '0', '/catalog/University_Favicon/usa/University of North Alabama_Favicon.png', 'Florence, Alabama, USA', 'University of North Alabama is a public university offering undergraduate and graduate programs across arts, science, and business.', 'https://www.una.edu', 'Not ranked globally', '1830', '8000'),
(337, 'University of North Texas at Denton', 'United States', '0', '/catalog/University_Favicon/usa/University of North Texas_Favicon.png', 'Denton, Texas, USA', 'University of North Texas is a large public research university known for music, business, and engineering programs.', '', 'Top 1000 (QS)', '1890', '46000'),
(338, 'University of Northampton', 'united kingdom', '/catalog/University_Banner/University of Northampton  Banner.png', '/catalog/University_Favicon/University of NorthamptonFavicon.png', 'Northampton, England', 'The University of Northampton is a public university located in Northampton, Northamptonshire, England. It?s known for its modern Waterside Campus, strong focus on student satisfaction and employability, and emphasis on applied learning and social impact. Established as a university in 2005, it has rapidly grown its reputation in teaching quality and community engagement. The institution prioritizes sustainability and inclusion in its programs.', 'https://www.northampton.ac.uk', '#1838 globally in the 2025 EduRank world university ranking', '2005', '10,000'),
(339, 'University of Northern British Columbia (UNBC)', 'Canada', '/catalog/University_Banner/canada-banner/UniversityofNorthernBritishColumbiabanner.png', '/catalog/University_Favicon/canada/University of Northern British Columbia Favicon.png', 'Prince George, British Columbia, Canada', 'University of Northern British Columbia (UNBC) is a public research university known for environmental science and sustainability research. It offers undergraduate and graduate programs with a strong focus on northern, rural, and Indigenous studies. UNBC emphasizes small class sizes, research collaboration, and community engagement.', 'https://www.unbc.ca', '#801?1000 in the world by THE World University Rankings', '1990', '4000'),
(340, 'University of Nottingham', 'united kingdom', '/catalog/University_Banner/University of Nottinghambanner.png', '/catalog/University_Favicon/University of NottinghamFavicon.png', 'Nottingham, England', 'The University of Nottingham is a public research university and a member of the Russell Group of leading research-intensive universities. It?s known for strong global research, diverse academic offerings, international collaborations, and a large student community spanning campuses in the UK, China, and Malaysia.', 'https://www.nottingham.ac.uk', '#97 in the world by QS World University Rankings', '1948', '40,000'),
(341, 'University of Oklahoma', 'United States', '0', '/catalog/University_logo//1723021378-University%20of%20Oklahoma_Favicon.png', 'Norman, Oklahoma', 'The University of Oklahoma (OU) is a public research university founded in 1890. It?s the flagship institution of the state, offering a wide range of undergraduate, graduate, and professional programs across three campuses (Norman, Oklahoma City, and Tulsa). OU is classified as an R1: Doctoral University with very high research activity and has notable programs in fields such as meteorology, petroleum engineering, law, and business.', 'https://www.ou.edu', '#240 in the world by EduRank', '1890', '34,523'),
(342, 'University of Portland', 'United States', '0', '0', 'Portland, Oregon, USA', 'University of Portland is a private Catholic university emphasizing academic excellence and ethical leadership. It offers strong programs in business, engineering, nursing, and liberal arts. The university is known for small class sizes, undergraduate focus, and strong student-faculty engagement.', 'https://www.up.edu', 'Not ranked in major global rankings', '1901', '4000'),
(343, 'University of Portsmouth', 'united kingdom', '/catalog/University_Banner/University of Portsmouth Banner1.png', '/catalog/University_Favicon/University of PortsmouthFavicon.png', 'Portsmouth, England, UK', 'University of Portsmouth is a public university known for high teaching quality and applied research. It offers programs across business, engineering, science, law, and creative industries. The university emphasizes innovation, student satisfaction, and employability. It has a vibrant coastal campus environment.', 'https://www.port.ac.uk', '501?550 (QS)', '1992', '28000'),
(344, 'University of Portsmouth - London Campus', 'united kingdom', '/catalog/University_Banner/University of Portsmouth Banner1.png', '/catalog/University_Favicon/University of PortsmouthFavicon.png', 'London, England, UK', 'University of Portsmouth ? London Campus provides career-focused postgraduate education in the capital city. It specializes in business, finance, law, and related professional programs. The campus emphasizes industry relevance, employability, and flexible learning. It complements the university?s main coastal campus.', 'https://www.port.ac.uk', '501?550 (QS)', '1992', '3000'),
(345, 'University of Potomac', 'United States', '0', '/catalog/University_Favicon/usa/University of Potomac_Favicon.png', 'Washington, District of Columbia', 'University of the Potomac is a private for-profit university offering flexible undergraduate, graduate, and doctoral programs designed for career advancement and adult learners. It provides options for on-campus, online, and hybrid learning and emphasizes practical, workforce-oriented education across business, technology, health information, and related fields. The university is accredited by the Middle States Commission on Higher Education (MSCHE).', 'https://www.potomac.edu', '#8329 in the world by Webometrics', '1991', '1,600'),
(346, 'University of Reading', 'united kingdom', '0', '/catalog/University_logo/University of Reading.jpg', 'Reading, England, UK', 'University of Reading is a public research university with strengths in agriculture, business, and climate science.', 'https://www.reading.ac.uk', '201?250 (QS)', '1892', '27000'),
(347, 'University of Redlands', 'United States', '0', '0', 'Redlands, California', 'The University of Redlands is a private liberal arts and sciences university offering undergraduate and graduate programs across liberal arts, business, education, music, science, theology, and more. It emphasizes personalized education, community engagement, small class sizes, and experiential learning. The campus is suburban and near the San Bernardino Mountains in Southern California.', 'https://www.redlands.edu', '#3704 in the world by Webometrics', '1907', '3,192'),
(348, 'University of Regina', 'Canada', '/catalog/University_Banner/canada-banner/UniversityofReginabanner.png', '/catalog/University_Favicon/canada/University of Regina Favicon.png', 'Regina, Saskatchewan, Canada', 'University of Regina is a public research university offering undergraduate and graduate programs. It is known for business, engineering, education, social sciences, and Indigenous studies. The university emphasizes experiential learning, co-op education, research, and community engagement.', 'https://www.uregina.ca', '#1201?1500 in the world by THE World University Rankings', '1911', '16000'),
(349, 'University of Roehampton', 'united kingdom', '0', '/catalog/University_Favicon/University of Roehampton_Favicon.png', 'London, England', 'The University of Roehampton is a public research university located in south-west London, England. It evolved from four historic teacher training colleges and became an independent university in 2004, later renamed the University of Roehampton in 2011. The campus is set in parkland and offers a variety of undergraduate and postgraduate programs with a focus on teaching quality and student experience. Roehampton is known for strong student satisfaction and applied learning opportunities.', 'https://www.roehampton.ac.uk', '#1469 globally in the 2025 EduRank world university ranking.', '2004', '11,170'),
(350, 'University of Saint Mary', 'United States', '0', '0', 'Leavenworth, Kansas', 'The University of Saint Mary is a private Catholic liberal arts university located in Leavenworth, Kansas, United States. Founded in 1923 by the Sisters of Charity of Leavenworth, it offers undergraduate, graduate, and doctoral programs with a focus on value-centered education, community, and personalized student support. USM emphasizes small class sizes, faith-inspired learning, and career preparation across disciplines like business, nursing, and education.', 'https://www.stmary.edu', '#4912 globally (EduRank World University Rankings 2025)', '1923', '1,414'),
(351, 'University of Salford', 'united kingdom', '/catalog/University_Banner/Universityof SalfordBanner.png', '/catalog/University_Favicon/University of SalfordFavicon.png', 'Salford, England, UK', 'University of Salford is a public university known for its strong industry connections and applied research. It offers programs in business, engineering, media, health, and sciences with a focus on real-world learning. The university emphasizes employability, innovation, and professional practice.', 'https://www.salford.ac.uk', '#801?1000 in the world by THE World University Rankings', '1896', '21000'),
(352, 'University of Sheffield', 'united kingdom', '/catalog/University_Banner/University of Sheffield-banner.png', '/catalog/University_Favicon/University of SheffieldFavicon.png', 'Sheffield, England', 'The University of Sheffield is a public research university located in Sheffield, England, UK. It?s a member of the prestigious Russell Group of research-intensive universities and is known for its high-quality teaching, impactful research, and diverse international student community. Sheffield offers a wide range of undergraduate and postgraduate programs across sciences, engineering, arts, business, and health disciplines, with a strong emphasis on employability and global engagement.', 'https://sheffield.ac.uk/', '#92 in the world by QS World University Rankings', '1905', '29666'),
(353, 'University of South Alabama', 'United States', '0', '/catalog/University_Favicon/usa/University of South Alabama_Favicon.png', 'Mobile, Alabama, USA', 'University of South Alabama is a public research university offering comprehensive undergraduate, graduate and professional programs. It has notable medical, engineering, business, and arts & sciences faculties. The university supports research, community outreach, and real-world training opportunities for its diverse student body.', 'https://www.southalabama.edu', 'Ranked in US regional/national lists (varies by source)', '1963', '14,000'),
(354, 'University of South Carolina', 'United States', '0', '/catalog/University_Favicon/usa/University of South Carolina_Favicon.png', 'Columbia, South Carolina, USA', 'University of South Carolina is a large public research university offering comprehensive academic programs. It is well known for business, engineering, public health, and international studies. The university emphasizes research, innovation, and experiential learning with strong global and industry partnerships.', 'https://sc.edu', '#601?650 in the world by QS World University Rankings', '1801', '35000');
INSERT INTO `university` (`id`, `name`, `country`, `banner_image`, `logo_image`, `city`, `description`, `link`, `ranking`, `established_year`, `enroll_students`) VALUES
(355, 'University of South Wales', 'united kingdom', '/catalog/University_Banner/University of South Wales  banner.png', '/catalog/University_Favicon/University of South WalesFavicon.png', 'Pontypridd, Wales, UK', 'University of South Wales is a large public university formed through the merger of multiple institutions. It offers programs across business, engineering, health, computing, creative industries, and social sciences. The university is known for strong industry links and applied learning. It plays a major role in regional economic development.', 'https://www.southwales.ac.uk', '1201?1500 (THE)', '2013', '23000'),
(356, 'University of Southampton', 'united kingdom', '0', '/catalog/University_Favicon/University of Southampton_Favicon.png', 'Southampton, England, UK', 'University of Southampton is a leading public research university and a member of the Russell Group. It is internationally recognized for research excellence in engineering, sciences, medicine, and social sciences. The university offers strong global partnerships, innovative research, and a vibrant campus life.', 'https://www.southampton.ac.uk', '#81 in the world by QS World University Rankings', '1862', '22000'),
(357, 'University of St. Thomas', 'United States', '0', '/catalog/University_Favicon/usa/University of St. Thomas_Favicon.png', 'Saint Paul & Minneapolis, Minnesota', 'The University of St. Thomas (Minnesota) is a private Catholic university known for its comprehensive liberal arts and professional programs across business, education, engineering, arts & sciences, health sciences, and more. It emphasizes engaged learning, strong student outcomes, and a values-driven education. UST is one of the largest private universities in Minnesota and serves students from across the U.S. and around the world.', 'https://www.stthomas.edu', '#1620 in the world by EduRank', '1885', '9,000'),
(358, 'University of Staffordshire', 'united kingdom', '/catalog/University_Banner/Staffordshire University  Banner.png', '/catalog/University_Favicon/StaffordshireUniversityFavicon.png', 'Stoke-on-Trent, England', 'Staffordshire University is a public university in Staffordshire, England, UK, known for its career-focused and industry-linked programmes in areas like digital technologies, creative arts, health, and business. It has multiple campuses with the main location in Stoke-on-Trent and is recognised for practical learning and strong subject performance in fields such as criminology and design. The university emphasizes hands-on education, student satisfaction and regional engagement.', 'https://www.staffs.ac.uk', '#1389 globally in the EduRank World University Rankings', '1992', '15,000'),
(359, 'University of Stirling', 'united kingdom', '/catalog/University_Banner/University of Stirling Banner.png', '/catalog/University_Favicon/University of StirlingFavicon.png', 'Stirling, Scotland, UK', 'University of Stirling is a public research university known for interdisciplinary teaching and research. It offers strong programs in business, sports science, social sciences, health, and environmental studies. The university emphasizes research excellence, student experience, and sustainability. It has a scenic campus with a strong global reputation.', 'https://www.stir.ac.uk', 'Top 500 (QS)', '1967', '14500'),
(360, 'University of Strathclyde', 'united kingdom', '/catalog/University_Banner/University of Strathclyde   Banner.png', '/catalog/University_Favicon/University of StrathclydeFavicon.png', 'Glasgow, Scotland', 'The University of Strathclyde is a public research university located in Glasgow, Scotland, UK. Established in 1796 as the Andersonian Institute, it has grown into a leading global technological university known for high-impact research, strong industry partnerships, and practical education across disciplines like engineering, business, science, and the humanities. Strathclyde emphasizes innovation, sustainability, and graduate employability in a dynamic urban setting.', 'https://www.strath.ac.uk', '#251 (QS World University Rankings 2026)', '1796', '17727'),
(361, 'University of Sunderland (London Campus)', 'united kingdom', '/catalog/University_Banner/University of Sunderland (London Campus)  Banner (1).png', '/catalog/University_Favicon/University of Sunderland (London Campus)Favicon.png', 'London, England, UK', 'University of Sunderland ? London Campus offers career-focused business, finance, and management programs.', 'https://www.sunderland.ac.uk', 'Top 1000 (QS)', '1901', '2000'),
(362, 'University of Sunderland (Sunderland Campus)', 'united kingdom', '/catalog/University_Banner/University of Sunderland (Sunderland Campus) banner.png', '/catalog/University_Favicon/University of Sunderland (London Campus)Favicon.png', 'Sunderland, England, UK', 'University of Sunderland is a public university with a strong focus on widening participation and employability. It offers programs in business, engineering, health sciences, computing, and media. The university emphasizes practical learning and student support. It serves both local and international students across multiple campuses.', 'https://www.sunderland.ac.uk', '1001?1200 (THE)', '1901', '20000'),
(363, 'University of Surrey', 'united kingdom', '/catalog/University_Banner/University of Surrey banner.png', '/catalog/University_Favicon/University of SurreyFavicon.png', 'Guildford', 'The University of Surrey is a public research university located in Guildford, England, UK, known for strong research, professional education, and high student satisfaction. It offers a wide range of undergraduate and postgraduate programs and emphasises industry connections, practical experience, and global engagement. Surrey has developed a strong reputation in fields like engineering, business, hospitality management, health sciences, and telecommunications.', 'https://www.surrey.ac.uk', '#262 (QS World University Rankings 2026)', '1966', '11987'),
(364, 'University of Sussex', 'united kingdom', '/catalog/University_Banner/University of Sussex Banner.png', '/catalog/University_Favicon/University of SussexFavicon.png', 'Falmer, near Brighton, England', 'The University of Sussex is a public research university located in Falmer (near Brighton), England, United Kingdom, known for its strong research focus, innovative teaching, and international outlook. It was established in 1961 and offers a wide range of undergraduate, postgraduate, and research programs across arts, sciences, social sciences, and engineering. Sussex is recognised for its impact in areas like sustainability and development studies and hosts a diverse global student community.', 'https://www.sussex.ac.uk', '#278 globally in the QS World University Rankings', '1961', '17,765'),
(365, 'University of Texas at San Antonio', 'United States', '0', '0', 'San Antonio, Texas', 'The University of Texas at San Antonio (UTSA) is a public research university and part of the University of Texas System, classified as an R1 ?very high research activity? institution with strong emphasis on research, innovation, student success, and community engagement. It?s the largest university in San Antonio and a Hispanic-Serving Institution.', 'https://www.utsa.edu', '#722 in the world by CWUR', '1969', '38,223'),
(366, 'University of the Pacific', 'United States', '0', '/catalog/University_Favicon/usa/University of the Pacific_Favicon.png', 'Stockton, California, USA', 'University of the Pacific is a private university with strong professional and liberal arts programs. Its schools include business, education, engineering, health sciences, and music. The university is known for individualized education, hands-on learning, and strong career outcomes for graduates.', 'https://www.pacific.edu', 'Ranked in US national/regional lists', '1851', '6,800'),
(367, 'University of Utah', 'United States', '0', '/catalog/University_Favicon/usa/University of Utah_Favicon.png', 'Salt Lake City, Utah, USA', 'University of Utah is a large public research university known for innovation, entrepreneurship, and strong research output. It offers a wide range of undergraduate, graduate, and professional programs, particularly strong in medicine, engineering, business, and sciences. The university supports interdisciplinary research and community engagement.', 'https://www.utah.edu', '#441 in the world by QS World University Rankings', '1850', '35000'),
(368, 'University of Waikato', 'new Zealand', '0', '/catalog/University_Favicon/nz/University of Waikato_Favicon.png', 'Hamilton, New Zealand', 'University of Waikato is a public research university well known for management, education, and computer science.', 'https://www.waikato.ac.nz', 'Top 250 (QS)', '1964', '13000'),
(369, 'University of Wales Trinity Saint David', 'united kingdom', '0', '/catalog/University_logo//1723019608-University%20of%20Wales%20Trinity%20Saint%20David_Favicon.png', 'Lampeter, Carmarthen & Swansea, Wales, UK', 'University of Wales Trinity Saint David is a public university formed through historic mergers, offering a broad range of undergraduate and postgraduate courses. It focuses on student satisfaction, supportive teaching, and skill development. Small classes and community engagement help personalise the learning experience for diverse academic interests.', 'https://www.uwtsd.ac.uk', 'Ranked (national UK guides; not globally ranked) (Wikipedia)', '2010', '10,000'),
(370, 'University of West Florida', 'United States', '0', '/catalog/University_Favicon/usa/University of West Florida_Favicon.png', 'Pensacola, Florida, USA', 'University of West Florida is a public university known for its strong academic programs and coastal research focus. It offers degrees in business, engineering, education, health, and sciences. The university emphasizes experiential learning, community engagement, and regional impact.', 'https://www.uwf.edu', 'Not ranked in major global rankings', '1963', '13000'),
(371, 'University of West London', 'united kingdom', '/catalog/University_Banner/University of West London  banner.png', '/catalog/University_Favicon/University of West LondonFavicon.png', 'London, England, UK', 'University of West London is a public university known for strong teaching quality and student satisfaction. It offers programs in business, hospitality, computing, music, health, and engineering. The university emphasizes employability, industry engagement, and practical learning. It has a strong reputation for career-focused education.', 'https://www.uwl.ac.uk', '1001?1200 (THE)', '1860', '12000'),
(372, 'University of West of England', 'united kingdom', '/catalog/University_Banner/University of West of England   Banner (1).png', '/catalog/University_Favicon/University of West of EnglandFavicon.png', 'Bristol, England, UK', 'University of the West of England (UWE Bristol) is a public university known for practice-based learning and strong industry links. It offers career-focused programs in business, engineering, health, creative industries, and technology. The university emphasizes employability, innovation, and applied research.', 'https://www.uwe.ac.uk', '#801?1000 in the world by THE World University Rankings', '1992', '30000'),
(373, 'University of West of Scotland', 'united kingdom', '/catalog/University_Banner/University of West of Scotland Banner.png', '/catalog/University_Favicon/University of West of ScotlandFavicon.png', 'Paisley & Ayr, Scotland, UK', 'University of the West of Scotland is a public university serving students across multiple campuses. It offers programs in business, engineering, computing, health, education, and social sciences. The university emphasizes widening access, applied research, and industry collaboration. It has a strong regional and international student base.', 'https://www.uws.ac.uk', '1201?1500 (THE)', '1897', '19000'),
(374, 'University of Westminster', 'united kingdom', '/catalog/University_Banner/University of Westminster-banner.png', '/catalog/University_Favicon/University of WestminsterFavicon.png', 'London, England, UK', 'University of Westminster is a public university offering a wide range of career-focused programs in business, media, law, arts, and sciences. Located in central London, it has strong links with industry and professional bodies. The university emphasizes practical learning, global outlook, and student diversity.', 'https://www.westminster.ac.uk', '#801?1000 in the world by THE World University Rankings', '1838', '19000'),
(375, 'University of Wisconsin - Eau Claire', 'United States', '0', '0', 'Eau Claire, Wisconsin', 'The University of Wisconsin?Eau Claire (UW-Eau Claire) is a public university in the University of Wisconsin System, offering more than 200 academic programs with strengths in education, business, nursing, engineering, psychology, sciences, and liberal arts. It?s known for its emphasis on undergraduate research, study abroad participation, and strong student success outcomes ? including national recognition for undergraduate research involvement and return-on-investment outcomes for graduates.', 'https://www.uwec.edu', '#1595 in the world by EduRank', '1916', '9,465'),
(376, 'University of Wisconsin - Platteville', 'United States', '0', '0', 'Platteville, Wisconsin, USA', 'University of Wisconsin?Platteville is a public university known for engineering, agriculture, and applied sciences.', 'https://www.uwplatt.edu', 'Not ranked globally', '1866', '7500'),
(377, 'University of Wisconsin - River Falls', 'United States', '0', '0', 'River Falls, Wisconsin', 'The University of Wisconsin?River Falls (UW?River Falls) is a public university and part of the University of Wisconsin System. Founded in 1874, it offers undergraduate and graduate programs across more than 70 areas of study, emphasizing personalized attention, applied learning, research, and professional preparation. UWRF has strengths in agriculture, education, sciences, business, and liberal arts, and participates in NCAA Division III athletics as the Falcons.', 'https://www.uwrf.edu', '#2772 in the world by EduRank', '1874', '5,275'),
(378, 'University of Wisconsin - Stout', 'United States', '0', '/catalog/University_Favicon/usa/University of Wisconsin - Stout_Favicon.png', 'Menomonie, Wisconsin, USA', 'University of Wisconsin?Stout is a public polytechnic university known for applied learning and career preparation. It offers undergraduate and graduate programs with strengths in engineering, technology, design, business, and education. The university emphasizes hands-on experience, internships, and industry collaboration.', 'https://www.uwstout.edu', 'Not ranked in major global rankings', '1891', '9500'),
(379, 'University of Wisconsin - Superior', 'United States', '0', '0', 'Superior, Wisconsin', 'University of Wisconsin?Superior (often UW?Superior) is a public liberal arts university in the University of Wisconsin System. It offers more than 50 undergraduate and graduate programs emphasizing small class sizes, personalized attention, and close student-faculty collaboration. The university is accredited and known for fields like elementary education, business, biology, psychology, communications, social work, and its unique transportation/mobility management program.', 'https://www.uwsuper.edu', '#3661 in the world by EduRank', '1893', '2,800'),
(380, 'University of Wisconsin - Whitewater', 'United States', '0', '/catalog/University_Favicon/usa/University of Wisconsin - Whitewater_Favicon.png', 'Whitewater, Wisconsin, USA', 'University of Wisconsin?Whitewater is a public university offering undergraduate and graduate programs across business, education, sciences, and arts. It is known for inclusive education, student support, and strong programs for students with disabilities. The university emphasizes applied learning and career preparation.', 'https://www.uww.edu', 'Not ranked in major global rankings', '1868', '12000'),
(381, 'University of Wollongong Dubai', 'united arab emirates', '0', '/catalog/University_logo//1723019505-University%20of%20Wollongong%20Dubai_Favicon.png', 'Dubai, United Arab Emirates', 'University of Wollongong Dubai is a branch campus of the University of Wollongong offering Australian degrees.', 'https://www.uowdubai.ac.ae', 'Top 200 (QS ? parent university)', '1993', '3500'),
(382, 'University of Wolverhampton', 'united kingdom', '/catalog/University_Banner/University of Wolverhampton banner.png', '/catalog/University_logo/University of Wolverhampton.jpg', 'Wolverhampton, England', 'The University of Wolverhampton is a public university in Wolverhampton, England, United Kingdom, with additional campuses in Walsall and Telford. It evolved from the Wolverhampton Tradesmen?s and Mechanics? Institute (est. 1827) and gained full university status in 1992. The university offers diverse undergraduate and postgraduate programs focused on employability, research impact, and inclusive education. It is known for strong community engagement and practical learning opportunities.', 'https://www.wlv.ac.uk', '#1120 globally (EduRank World University Rankings 2025)', '1827', '29,400'),
(383, 'University of Worcester', 'united kingdom', '/catalog/University_Banner/University of Worcester Banner.png', '/catalog/University_Favicon/University of WorcesterFavicon.png', 'Worcester, England', 'The University of Worcester is a public university known for its inclusive and student-centred approach, strong emphasis on quality teaching, excellent graduate employability, and community engagement. It offers a wide range of undergraduate and postgraduate programs across areas like health, education, sport science, business, arts & humanities, science and more.', 'https://www.worcester.ac.uk', '#2000 in the world by EduRank', '2005', '9,184'),
(384, 'University of Wyoming', 'United States', '0', '/catalog/University_Favicon/usa/University of Wyoming_Favicon.png', 'Laramie, Wyoming, USA', 'University of Wyoming is a public land-grant research university offering diverse undergraduate and graduate programs. It is strong in agriculture, engineering, business, education, and sciences. The university is known for personalized faculty engagement, research opportunities, and support for innovation and local community impact.', 'https://www.uwyo.edu', '#1201?1500 in the world by THE World University Rankings', '1886', '12000'),
(385, 'University of York', 'united kingdom', '/catalog/University_Banner/University of York  Banner.png', '/catalog/University_Favicon/University of York favicon .png', 'York, England, UK', 'University of York is a leading public research university and a member of the Russell Group. It is recognized for excellence in teaching, research, and interdisciplinary study. The university offers strong programs across humanities, sciences, social sciences, and business. It has a strong international academic reputation.', 'https://www.york.ac.uk', 'Top 150 (QS)', '1963', '20000'),
(386, 'university_name', 'country', '0', '0', 'Not specified', 'Placeholder entry for university name to be updated with actual institution details.', 'Not applicable', 'Not applicable', 'Not applicable', 'Not applicable'),
(387, 'USA Enquiry', 'United States', '0', '/catalog/University_Favicon/ireland/Enquiry_Favicon.png', 'United States', 'USA Enquiry is an education consultancy service assisting students with admissions to US institutions.', 'Not applicable', 'Not applicable', 'Not applicable', ''),
(388, 'Utah Tech University', 'United States', '0', '0', 'St. George, Utah', 'Utah Tech University is a public polytechnic university located in St. George, Utah, USA. It offers a wide range of associate, bachelor?s, master?s, and doctoral programs, with a strong emphasis on hands-on, career-oriented education, industry partnerships, and experiential learning. The university combines small class sizes with real-world experiences to prepare students for careers across disciplines like business, STEM, health sciences, and more. It officially became Utah Tech University after rebranding in 2022, building on more than a century of educational growth.', 'https://www.utahtech.edu', '#6562 (Webometrics 2025)', '1911', '13,167'),
(389, 'Victoria University - Melbourne Campus', 'Australia', '/catalog/University_Banner/Australia/VictoriaUniversity(Melbournecampus)banner.png', '/catalog/University_Favicon/australia/Victoria University_Favicon.png', 'Melbourne, Victoria, Australia', 'Victoria University ? Melbourne Campus is a public university offering flexible learning across multiple disciplines.', 'https://www.vu.edu.au', 'Top 800 (QS)', '1916', '45000'),
(390, 'Victoria University of Wellington', 'new Zealand', '/catalog/University_Banner/NewZealand/VictoriaUniversityofWellingtonbanner.png', '/catalog/University_Favicon/nz/Victoria University of Wellington_Favicon.png', 'Wellington, New Zealand', 'Victoria University of Wellington is a leading public research university with strong global reputation in law and humanities.', 'https://www.wgtn.ac.nz', 'Top 250 (QS)', '1897', '22000'),
(391, 'Virginia Wesleyan University', 'United States', '0', '0', 'Charlottesville, Virginia', 'Virginia Wesleyan University is a private liberal arts and sciences university rooted in a Methodist heritage, providing career-focused and experiential education across a range of undergraduate and graduate programs. Situated on a 300-acre campus in coastal Virginia, it emphasizes small-group learning, global engagement, and community involvement.', 'https://www.vwu.edu', '#4,523 in the world (EduRank 2025 global ranking)', '1819', '24360'),
(392, 'Washington and Jefferson College', 'United States', '0', '0', 'Washington, Pennsylvania', 'Washington & Jefferson College (often W&J) is a private liberal arts college with roots going back to the late 18th century. It was formed by the merger of Washington College and Jefferson College in 1865, with original founding activity dating back to 1781. The college is known for its strong emphasis on undergraduate liberal arts education, close student-faculty collaboration, research opportunities, and personalized academic programs. Many students live on campus, and the college competes in NCAA Division III athletics as the Presidents.', 'https://www.washjeff.edu', '#3581 in the world by EduRank', '1781', '1,309'),
(393, 'Washington State University', 'United States', '0', '0', 'Pullman, Washington', 'Washington State University (WSU) is a public land-grant research university and one of the oldest in the American West, known for strong programs in agriculture, engineering, business, health sciences, veterinary medicine, communication, science, and more, as well as extensive research and community engagement. It is classified as an R1: Doctoral University ? very high research activity and operates multiple campuses across Washington plus an online Global Campus.', 'https://www.wsu.edu', '#423 in the world by QS World University Rankings', '1890', '31,471'),
(394, 'Webster University', 'United States', '0', '0', 'St. Louis, Missouri, USA', 'Webster University is a private nonprofit university with a strong global presence. It offers undergraduate and graduate programs in business, international relations, media, education, and arts. The university emphasizes global education, experiential learning, and flexible study options.', 'https://www.webster.edu', 'Not ranked in major global rankings', '1915', '12000'),
(395, 'Wellington Institute of Technology (WelTec)', 'new Zealand', '/catalog/University_Banner/NewZealand/WellingtonInstituteofTechnology(WelTec)banner.png', '/catalog/University_Favicon/nz/Wellington Institute of Technology_Favicon.png', 'Lower Hutt & Wellington, New Zealand', 'Wellington Institute of Technology (WelTec) is a public institute offering vocational and applied degree programs.', 'https://www.weltec.ac.nz', 'Not ranked globally', '1904', '6000'),
(396, 'Western Illinois University', 'United States', '0', '/catalog/University_logo//1723020299-Western%20Illinois%20University_Favicon.png', 'Macomb, Illinois', 'Western Illinois University (WIU) is a public co-educational university offering more than 100 undergraduate and graduate programs across arts and sciences, business, education, technology, and more, with campuses in Macomb and the Quad Cities (Moline) region.', 'https://www.wiu.edu', '#1638 in the world by EduRank', '1899', '6,000'),
(397, 'Western New England University', 'United States', '0', '/catalog/University_Favicon/usa/Western New England University_Favicon.png', 'Springfield, Massachusetts, USA', 'Western New England University is a private university known for its professional programs in law, business, engineering, and health sciences. It integrates practical experience with academic study, emphasising internships and career preparation. The campus fosters interdisciplinary collaboration and leadership development.', 'https://www.wne.edu', 'Ranked in US regional lists', '1919', '3,500'),
(398, 'Western Oregon University', 'United States', '0', '0', 'Monmouth, Oregon, USA', 'Western Oregon University is a public university offering undergraduate and graduate programs with a strong focus on teaching and student support. It is known for education, liberal arts, business, and sciences. The university emphasizes small class sizes, experiential learning, and regional community engagement.', 'https://www.wou.edu', 'Not ranked in major global rankings', '1856', '4500'),
(399, 'Western Washington University', 'United States', '0', '0', 'Bellingham, Washington', 'Western Washington University (WWU) is a public comprehensive university known for its strong liberal arts and sciences programs, hands-on learning, commitment to sustainability, and community engagement.', 'https://www.wwu.edu', '#954 in the world (EduRank)', '1893', '16,142'),
(400, 'Whitireia Community Polytechnic', 'new Zealand', '/catalog/University_Banner/NewZealand/WhitireiaCommunityPolytechnicbanner.png', '/catalog/University_Favicon/nz/Whitireia Community Polytechnic_Favicon.png', 'Porirua & Wellington, New Zealand', 'Whitireia Community Polytechnic is a public institute known for health, arts, and trades education.', 'https://www.whitireia.ac.nz', 'Not ranked globally', '1986', '6500'),
(401, 'Whittier College', 'United States', '0', '0', 'Whittier, California, USA', 'Whittier College is a private liberal arts college offering undergraduate programs with a strong focus on experiential learning. It emphasizes small class sizes, diversity, and community engagement. The college prepares students for leadership, graduate study, and professional success.', 'https://www.whittier.edu', 'Not ranked in major global rankings', '1887', '1400'),
(402, 'Wichita State University', 'United States', '0', '/catalog/University_Favicon/usa/Wichita State University_Favicon.png', 'Wichita, Kansas', 'Wichita State University (WSU) is a public research university offering more than 60 undergraduate and graduate programs across arts, sciences, business, engineering, education and more. It is classified as an ?R2: Doctoral Universities ? High research activity? institution and known for strong applied learning, innovation partnerships, and industry collaborations.', 'https://www.wichita.edu', '#884 in the world by EduRank', '1895', '25,147'),
(403, 'William Paterson University', 'United States', '0', '0', 'Wayne, New Jersey, USA', 'William Paterson University is a public university offering undergraduate and graduate programs across arts, sciences, business, and education. It focuses on career-oriented education, applied learning, and accessibility. The university emphasizes student support, internships, and regional workforce development.', 'https://www.wpunj.edu', 'Not ranked in major global rankings', '1855', '9500'),
(404, 'Wilson College', 'United States', '0', '0', 'Chambersburg, Pennsylvania', 'Wilson College is a private liberal arts college affiliated historically with the Presbyterian Church (USA). Founded in 1869 as a women?s college and becoming coeducational in 2013, it offers undergraduate and graduate programs with a strong liberal arts foundation, career-oriented curricula, and growing online education options. The college emphasizes personalized attention, small classes, and community engagement.', 'https://www.wilson.edu', '#4391 in the world by EduRank', '1869', '1,705'),
(405, 'Wrexham Glyndwr University', 'united kingdom', '0', '/catalog/University_logo/Wrexham Glyndwr University.jpg', 'Wrexham, Wales, UK', 'Wrexham Glynd?r University is a public university focused on applied and career-oriented education. It offers programs in engineering, computing, business, health, and creative industries. The university emphasizes small class sizes, strong student support, and practical learning approaches. It plays a key role in regional development and employability.', 'https://www.glyndwr.ac.uk', '1201?1500 (THE)', '2008', '6500'),
(406, 'Wright State University', 'United States', '0', '/catalog/University_Favicon/usa/Wright State University_Favicon.png', 'Dayton, Ohio', 'Wright State University is a public research university located in Fairborn, Ohio, USA, near Dayton. Named after aviation pioneers the Wright brothers, it offers a wide range of undergraduate, graduate, doctoral and professional programs across multiple colleges and a medical school. The university emphasizes accessible and affordable education with strong community, research, and career outcomes. It also operates a branch campus at Wright State University?Lake Campus in Celina, Ohio.', 'https://www.wright.edu', '#720 globally (EduRank 2025)', '1967', '15558'),
(407, 'Yeshiva University', 'United States', '0', '/catalog/University_Favicon/usa/Yeshiva University_Favicon.png', 'New York City', 'Yeshiva University (YU) is a private Jewish research university combining Jewish scholarship with academic excellence across liberal arts, sciences, medicine, law, business, social work, psychology, and education. Founded with roots in Talmudic study, it now includes undergraduate schools (like Yeshiva College, Stern College for Women, and Sy Syms School of Business) and multiple graduate/professional schools such as Cardozo School of Law, Katz School of Science and Health, Wurzweiler School of Social Work, Ferkauf Graduate School of Psychology, and affiliates like Albert Einstein College of Medicine. Instruction and scholarship blend secular and Jewish learning.', 'https://www.yu.edu', '#270 in the world by CWUR', '1886', '6,115'),
(408, 'York College of Pennsylvania', 'United States', '0', '0', 'Spring Garden Township, Pennsylvania', 'York College of Pennsylvania is a private liberal arts college located in Spring Garden Township, near York, Pennsylvania, USA. Established from the historic **York County Academy in 1787, it offers over 70 majors focused on professional programs, sciences, and humanities with a strong emphasis on personalized teaching and career preparation. The college features small class sizes, a student-centered environment, and active campus life with NCAA Division III athletics.', 'https://www.ycp.edu', '#2963 globally in the EduRank World University Rankings', '1787', '3,825'),
(409, 'York St John University - London Campus', 'united kingdom', '0', '/catalog/University_Favicon/York St John University_Favicon.png', 'London, England, UK', 'York St John University ? London Campus offers business and management programs from York St John University.', 'https://www.yorksj.ac.uk', 'Not ranked globally', '1841', '1000'),
(410, 'York St John University - York Campus', 'united kingdom', '0', '/catalog/University_Favicon/York St John University_Favicon.png', 'York, England', 'York St John University is a public university located in York, England, UK, offering a range of undergraduate, postgraduate and research programmes with a focus on student experience, inclusive learning, and community engagement. It traces its roots back to 1841 as an Anglican teacher training college and gained full university status in 2006. The York Campus is the main campus set in a historic city centre, providing modern facilities and strong student support.', 'https://www.yorksj.ac.uk', '#2374 globally according to EduRank World University Rankings', '1841', '8,300'),
(411, 'Youngstown State University', 'United States', '0', '/catalog/University_Favicon/usa/Youngstown State University_Favicon.png', 'Youngstown, Ohio', 'Youngstown State University is a public university offering a wide range of undergraduate and graduate programs. It is known for engineering, business, education, and liberal arts programs with a focus on applied learning. The university supports research, internships, and strong ties to regional industries.', 'https://www.ysu.edu', '#2500+ in the world by EduRank', '1908', '11000');
